-- SUPPRESSION des hadiths / invocations / dhikr importés depuis islam.ms (seeding 005).
-- Retire uniquement les entrées dont le texte arabe correspond exactement à l'import
-- islam.ms. Les entrées d'origine et tout autre contenu ne sont PAS touchés.
-- À exécuter dans l'éditeur SQL de Supabase.

BEGIN;

-- hadith : 70 entrées
SELECT count(*) AS "hadith_a_supprimer" FROM "hadith" WHERE texte_arabe IN (
  '"أبو بكر في الجنة وعمرُ في الجنة وعثمانُ في الجنة وعليٌ في الجنة وطلحةُ بن عبيدِ اللهِ في الجنة والزبيرُ بنُ العوامِ في الجنة وأبو عبيدةُ عامرُ بنُ الجراحِ في الجنة وسعدُ بن أبي وقاصٍ في الجنة وسعيد بن زَيدٍ في الجنة وعبد الرحمنِ بنُ عوفٍ في الجنة".',
  '« ائتني بها »',
  '« أعتقها فإنها مؤمنة »',
  '« أتشهدين أن لا إله إلا الله »',
  '« أتشهدين أني رسول الله »',
  '« أمرت أن أقاتل الناس حتى يشهدوا أن لا إله إلا الله وأني رسول الله »',
  '« إِنْ رَحْمَتِي سَبَقَتْ غَضَبِي »',
  '« لما خلق الله الخلق كتب في كتاب يكتبه على نفسه وهو موضوع فوق العرش إن رحمتي تغلب غضبي »',
  '«إِذَا كَانَ أَحَدُكُمْ فِي صَلَاتِهِ فَإِنَّهُ يُنَاجِي رَبَّهُ فَلَا يَبْصُقَنَ فِي قِبْلَتِهِ وَلَا عَنْ يَمِينِهِ فَإِنَّ رَبَّهُ بَيْنَهُ وَبَيْنَ قِبْلَتِهِ »',
  '« ارْبَعُوا عَلَى أَنْفُسِكُمْ فَإِنَّكُمْ لَا تَدْعُونَ أَصَمَّ وَلَا غَائِباً إِنَّكُم تَدْعُونَ سَمِيعاً قَريباً والذي تدعونَهُ أَقْرَبُ إِلَى أَحَدِكُمْ مِنْ عُنْقِ رَاحِلَةِ أَحَدِكُم »',
  '« الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَنُ ارْحَمُوا مَنْ فِي الْأَرْضِ يَرْحَمكُمْ مَنْ فِي السَّمَاءِ »',
  '« يَرْحَمْكُمْ أَهْلُ السَّمَاءِ »',
  '« الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَنُ ارْحَمُوا أَهْلَ الْأَرْضِ يَرْحَمْكُمْ أَهْلُ السَّمَاءِ »',
  '« ما في السماء موضع أربع أصابع إلا وفيه ملك قائم أو راكع أو ساجد »',
  '« أَلَا تَأْمَنُونِي وَأَنَا أَمِينُ مَنْ فِي السَّمَاءِ يَأْتِينِي خَبَرُ مَنْ فِي السَّمَاءِ صَبَاحاً وَمَسَاءً »',
  '« زَوْجَكُنَّ أَهَالِيكُنَّ وَزَوْجَنِيَ اللهُ مِنْ فَوْقِ سَبْعِ سَمَوَاتِ »',
  '« وَالَّذِي نَفْسِي بِيَدِهِ مَا مِنْ رَجُلٍ يَدْعُو امْرَأَتَهُ إِلَى فِرَاشِهِ فتَأْبَى عَلَيْهِ إِلَّا كَانَ الَّذِي فِي السَّمَاءِ سَاخِطَا عَلَيْهَا .... »',
  '« لَعَنَتْهَا الْمَلَائِكَةُ حَتَّى تُصْبِحَ »',
  '« رَبَّنَا الَّذِي فِي السَّمَاءِ تَقَدَّسَ اسْمُكَ »',
  '« إِنَّ اللهَ عَلَى عَرْشِهِ فَوْقَ سَمَوَاتِهِ، وَسَمَوَاتُهُ فَوْقَ أَرَاضِيهِ مِثْلُ الْقُبة »',
  '« لَمَّا كَلَّمَ اللهُ مُوسَى كَانَ نِدَاؤُهُ فِي السَّمَاءِ وَكَانَ اللهُ فِي السَّمَاءِ »',
  '« حتى يشهدوا أَن لاَّ إِلـه إلاَّ الله وأنِّي رَسُولُ الله »',
  '« إرحمُو من في الأرضِ يَرحَمُكُم من في السَّماء »',
  '« إرحمُو أهلَ الأرضِ يَرحَمُكُم أهلُ السَّماء »',
  '« وَقَالَ إِنِّي ذَاهِبٌ إِلَى رَبِّي سَيَهْدِينِ »',
  '« فَأَيْنَمَا تُوَلُّواْ فَثَمَّ وَجْهُ اللّهِ »',
  '« الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى »',
  '« قُلْ هَلْ يَسْتَوِي الَّذِينَ يَعْلَمُونَ وَالَّذِينَ لا يَعْلَمُونَ »',
  '« وما تقرّبَ إليَّ عبدي بشيءٍ أَحَبَّ إليَّ ممّا افترضتُ عليه »',
  '« لقد سألتَ عن عظيمٍ وإنه لَيسيرٌ على مَن يسّره اللهُ تعالى عليه تعبدُ اللهَ لا تُشرِكُ به شيئٌا وتُقيم الصلاةَ وتُؤتي الزكاةَ وتصومُ رمضانَ وتحُجُّ البيتَ إنِ استطعتَ إليه سبيلًا »',
  '« العبادة في الهَرْجِ كهِجْرةٍ إِلي »',
  'و في رواية قال : قال رسول الله صلى الله عليه وسلم : "يوشك أن يَحْسِرَ الفرات عن كنز من ذهب، فمن حضره فلا يأخذ منه شيئاً" متفق عليه (أي رَوَاهُ الْبُخَارِيُّ وَ مُسْلِمٌ)',
  'سَبْعَةٌ يُظِلُّهُمُ اللَّهُ فِي ظِلِّهِ يَوْمَ لاَ ظِلَّ إِلاَّ ظِلُّهُ',
  'ما مِنْ قَلْبٍ إِلا بَيْنَ إِصْبِعَيْنِ مِنْ أصَابِعِ الرَّحْمن إنْ شَاءَ أقَامَهُ وَإنْ شَاءَ أزَاغَهُ',
  '" يَنـزِلُ رَبُّنَا كُلَّ لَيْلَةٍ إِلَى السَّمَاءِ الدُّنْيَا "',
  'إن الله يمهل حتى يمضي شطر الليل الأول فيأمر مناديا فينادي …',
  '« يُنزِل ربٌّنا »',
  'وَمَنْ وَصَفَ اللهَ بِمَعْنًى مِنْ مَعَانِي البَشَر فَقَدْ كَفَر',
  '« اغتنم خمسا قبل خمسا اغتنم حياتك قبل موتك وصحتك قبل سقمك وشبابك قبل هرمك وغناك قبل فقرك وفراغك قبل شغلك »',
  'عن عائشة قالت : سألت رسول الله صلى الله عليه وسلم عن الالتفات في الصلاة فقال : « هو اختلاس (الأخذ بسرعة على غفلة) يختلسه الشيطان من صلاة العبد » رَوَاهُ البخاري',
  'عن أنس قال : قال لي رسول الله صلى الله عليه وسلم : « إياك والالتفات في الصلاة فإن الالتفات في الصلاة هلكة ، فإن كان لا بد ففي التطوع لا في الفريضة » رَوَاهُ الترمذي أي سبب الهلاك و ذلك لأن ارتكاب المكروهات قد يؤدي إلى ارتكاب المحرمات فيكون أهلك نفسه بتعريضها للعقاب',
  '« مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيا نَفَّسَ اللهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة، ومَنْ يَسَّرَ عَلى مُعْسِرٍ يَسَّرَ اللهُ عَلَيْهِ في الدُّنْيا والآخِرَةِ ومَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللهُ في الدُّنْيا والآخِرَةِ واللهُ في عَوْنِ العَبْدِ ما كانَ العَبْدُ في عَوْنِ أَخِيهِ ومَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللهُ بِهِ طَرِيقًا إِلى الجَنَّةِ وما اجْتَمَعَ قَوْمٌ في بَيْتٍ مِنْ بُيُوتِ اللهِ يَتْلُونَ كِتابَ اللهِ ويَتَدارَسُونَهُ بَيْنَهُمْ إِلاَّ نَزَلَتْ عَلَيْهِمُ السَّكِينَةُ وغَشِيَتْهُمُ الرَّحْمَةُ وحَفَّتْهُمُ الْمَلائِكَةُ وذَكَرَهُمُ اللهُ فِيمَنْ عِنْدَهُ ومَنْ بَطَّأَ بِهِ عَمَلُهُ لَمْ يُسْرِعْ بِهِ نَسَبُهُ »',
  '« مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيا نَفَّسَ اللهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة »',
  '« إِنَّما يَرْحَمُ اللهُ مِنْ عِبادِهِ الرُّحَماءَ »',
  '« إِنَّ اللهَ يُعَذِّبُ الَّذِينَ يُعَذِّبُونَ الناسَ في الدُّنْيا »',
  '« أَنَّ رَجُلاً مِنْ أَهْلِ الجَنَّةِ يُشْرِفُ يَوْمَ القِيامَةِ عَلى أَهْلِ النارِ، فَيُنادِيهِ رَجُلٌ مِنَ النارِ يا فُلانُ هَلْ تَعْرِفُنِي ؟ فَيَقُولُ لا واللهِ ما أَعْرِفُكَ مَنْ أَنْتَ ؟ فَيَقُولُ أَنا الَّذِي مَرَرْتَ بِهِ في دارِ الدُّنْيا فَٱسْتَسْقَيْتَنِي شُرْبَةً مِنْ ماءٍ فَسَقَيْتُكَ قالَ عَرَفْتُ. فَقالَ فَٱشْفَعْ لي بِها عِنْدَ رَبِّكَ، فَقالَ فَيَسْأَلُ اللهَ تَعالى فَيَقُولُ شَفِّعْنِي فِيهِ فَيُشَفَّعُ فِيهِ فَيَأْمُرُ بِهِ فَيُخْرَجُ مِنَ النار»',
  '« كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة »',
  '« يَعْرَقُ الناسُ يَوْمَ القِيامَةِ حَتَّى يَذْهَبَ عَرَقُهُمْ في الأَرْضِ سَبْعِينَ ذِراعًا، ويُلْجِمُهُمْ حَتَّى يَبْلُغَ ءاذانهم »',
  '« تُدْنَى الشَّمْسُ يَوْمَ القِيامَةِ مِنَ الخَلْقِ حَتَّى تَكُونَ مَنْهُمْ كَمِقْدارِ مِيلٍ فَيَكُونُ الناسُ عَلى قَدْرِ أَعْمالِهِمْ في العَرَقِ فَمِنْهُمْ مَنْ يَكُونُ إِلى كَعْبَيْهِ ومِنْهُمْ مَنْ يَكُونُ إِلى رُكْبَتَيْهِ ومِنْهُمْ مَنْ يَكُونُ إِلى حَقْوَيْهِ ومِنْهُمْ مَنْ يُلْجِمُهُ العَرَقُ إِلْجامًا »',
  '« كانَ تاجِرٌ يُدايِنُ الناسَ فَإِذا رَأَى مُعْسِرًا قالَ لِفِتْيانِهِ تَجاوَزُوا عَنْهُ لَعَلَّ اللهَ يَتَجاوَزُ عَنّا فَتَجاوَزَ اللهُ عَنْهُ »',
  '« ماتَ رَجُلٌ فَقِيلَ لَهُ بِمَ غَفَرَ اللهُ لَكَ ؟ فَقالَ كُنْتُ أُبايِعُ الناسَ فَأَتَجَوَّزُ عَنِ الْمُوسِرِ وأُخَفِّفُ عَنِ الْمُعْسِرِ »',
  '« مَنْ أَرادَ أَنْ تُسْتَجابَ دَعْوَتُهُ وأَنْ تُكْشَفَ كُرْبَتُهُ فَلْيُفَرِّجْ عَنْ مُعْسِرٍ »',
  '« وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللهُ في الدُّنْيا وَالآخِرَةِ »',
  '« وَاللهُ في عَوْنِ العَبْدِ ما كانَ العَبْدُ في عَوْنِ أَخِيهِ »',
  '« أَفْضَلُ الأَعْمالِ إِدْخالُ السُّرُورِ عَلَى الْمُؤْمِنِ، كَسَوْتَ عَوْرَتَهُ أَوْ أَشْبَعْتَ جَوْعَتَهُ أَوْ قَضَيْتَ حاجَتَهُ »',
  '« ومَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللهُ لَهُ بِهِ طَرِيقًا إِلى الجَنَّة »',
  '« ما جَلَسَ قَوْمٌ في بَيْتٍ مِنْ بُيُوتِ اللهِ يَتْلُونَ كِتابَ اللهِ ويَتَدارَسُونَهُ بَيْنَهُمْ إِلاَّ نَزَلَتْ عَلَيْهِمُ السَّكِينَةُ وغَشِيَتْهُمُ الرَّحْمَةُ وحَفَّتْهُمُ الْمَلائِكَةُ وذَكَرَهُمُ اللهُ فِيمَنْ عِنْدَهُ »',
  '« خَيْرُكُمْ مَنْ تَعَلَّمَ القُرْءانَ وعَلَّمَهُ »',
  '« ما مِنْ قَوْمٍ صَلُّوا صَلاةَ الغَداةِ ثُمَّ قَعَدُوا في مُصَلاّهُمْ يَتَعاطَوْنَ كِتابَ اللهِ ويَتَدارَسُونَهُ إِلاَّ وَكَّلَ اللهُ بِهِمْ مَلائِكَةً يَسْتَغْفِرُونَ لَهُمْ حَتَّى يَخُوضُوا في حَدِيثٍ غَيْرِهِ »',
  'ليس أمرًا عاديًا أن نرى طفلًا رضيعًا يتكلّم بكلام مفهم فصيح، ولكنَّ الله عزَّ وجلَّ يُظهِر بعض العجائب ليعتبر الناس ويتفكّروا ويتدبّروا، ومن هذه العجائب ما جرى مع إحدى الأمّهات التي كانت ترضع ولدها فحدثت أمامهما حادثة أخبرنا عنها النبيُّ الأعظم ﷺ وقد وقعت في إحدى الأمم السابقة.',
  'ثم سألت ولدها عن الشابّة التي كانت تُضرب فقال الطفل الرضيع: إن الشابّة كانت صالحة تقيّة، وقد افترى عليها بعض الناس زورًا وبهتانًا فصبرت وقالت: «حسبي الله ونعم الوكيل»، فدعوتُ الله أن يجعلني مثلها أي صابرًا محتسبًا، إن المغزى من هذه القصة أنّ بعض الناس قد يطلبون ما فيه مضرّتهم، والمطلوب ترك التكبّر والظلم كما أن المطلوب الصبر على الشدائد.',
  '« مَهْمَا تَصَوَّرْتَ بِباَلِكَ فَالله بِخِلافِ ذَالِك »',
  '« إِنَّ هَذا المالَ حُلْوَةٌ خَضِرَةٌ مَنْ أَخَذَهُ بِحَقِّهِ ووَضَعَهُ في حَقِّهِ فَنِعْمَ الْمَعُونَةُ هُوَ ومَنْ أَخَذَهُ بِغَيْرِ حَقِّهِ كانَ كَالَّذِي يَأْكُلُ ولا يَشْبَعُ »',
  '« نِعْمَ الْمالُ الصّالِحُ لِلرَّجُلِ الصّالِحِ »',
  '« ما نَفَعَنِي مالٌ قَطُّ ما نَفَعَنِي مالُ أَبِي بَكْرٍ »',
  '« مَا أَبْقَيْتَ لأَهْلِكَ »',
  'وَهَذَا لِسَانٌ عَرَبِيٌّ مُّبِينٌ',
  'لاَ يُقَالُ أَيْنَ لِمَنْ أَيَّنَ الأَيْنَ',
  '« إِذَا سَأَلْتَ فَاسْأَلِ اللهَ وَإِذَا اسْتَعَنْتَ فَاسْتَعِن باللهِ »',
  '« اللَّهُمَّ عَلِّمْهُ الحِكْمَةَ وَتَأْوِيلَ الكِتَابِ »'
);

DELETE FROM "hadith" WHERE texte_arabe IN (
  '"أبو بكر في الجنة وعمرُ في الجنة وعثمانُ في الجنة وعليٌ في الجنة وطلحةُ بن عبيدِ اللهِ في الجنة والزبيرُ بنُ العوامِ في الجنة وأبو عبيدةُ عامرُ بنُ الجراحِ في الجنة وسعدُ بن أبي وقاصٍ في الجنة وسعيد بن زَيدٍ في الجنة وعبد الرحمنِ بنُ عوفٍ في الجنة".',
  '« ائتني بها »',
  '« أعتقها فإنها مؤمنة »',
  '« أتشهدين أن لا إله إلا الله »',
  '« أتشهدين أني رسول الله »',
  '« أمرت أن أقاتل الناس حتى يشهدوا أن لا إله إلا الله وأني رسول الله »',
  '« إِنْ رَحْمَتِي سَبَقَتْ غَضَبِي »',
  '« لما خلق الله الخلق كتب في كتاب يكتبه على نفسه وهو موضوع فوق العرش إن رحمتي تغلب غضبي »',
  '«إِذَا كَانَ أَحَدُكُمْ فِي صَلَاتِهِ فَإِنَّهُ يُنَاجِي رَبَّهُ فَلَا يَبْصُقَنَ فِي قِبْلَتِهِ وَلَا عَنْ يَمِينِهِ فَإِنَّ رَبَّهُ بَيْنَهُ وَبَيْنَ قِبْلَتِهِ »',
  '« ارْبَعُوا عَلَى أَنْفُسِكُمْ فَإِنَّكُمْ لَا تَدْعُونَ أَصَمَّ وَلَا غَائِباً إِنَّكُم تَدْعُونَ سَمِيعاً قَريباً والذي تدعونَهُ أَقْرَبُ إِلَى أَحَدِكُمْ مِنْ عُنْقِ رَاحِلَةِ أَحَدِكُم »',
  '« الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَنُ ارْحَمُوا مَنْ فِي الْأَرْضِ يَرْحَمكُمْ مَنْ فِي السَّمَاءِ »',
  '« يَرْحَمْكُمْ أَهْلُ السَّمَاءِ »',
  '« الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَنُ ارْحَمُوا أَهْلَ الْأَرْضِ يَرْحَمْكُمْ أَهْلُ السَّمَاءِ »',
  '« ما في السماء موضع أربع أصابع إلا وفيه ملك قائم أو راكع أو ساجد »',
  '« أَلَا تَأْمَنُونِي وَأَنَا أَمِينُ مَنْ فِي السَّمَاءِ يَأْتِينِي خَبَرُ مَنْ فِي السَّمَاءِ صَبَاحاً وَمَسَاءً »',
  '« زَوْجَكُنَّ أَهَالِيكُنَّ وَزَوْجَنِيَ اللهُ مِنْ فَوْقِ سَبْعِ سَمَوَاتِ »',
  '« وَالَّذِي نَفْسِي بِيَدِهِ مَا مِنْ رَجُلٍ يَدْعُو امْرَأَتَهُ إِلَى فِرَاشِهِ فتَأْبَى عَلَيْهِ إِلَّا كَانَ الَّذِي فِي السَّمَاءِ سَاخِطَا عَلَيْهَا .... »',
  '« لَعَنَتْهَا الْمَلَائِكَةُ حَتَّى تُصْبِحَ »',
  '« رَبَّنَا الَّذِي فِي السَّمَاءِ تَقَدَّسَ اسْمُكَ »',
  '« إِنَّ اللهَ عَلَى عَرْشِهِ فَوْقَ سَمَوَاتِهِ، وَسَمَوَاتُهُ فَوْقَ أَرَاضِيهِ مِثْلُ الْقُبة »',
  '« لَمَّا كَلَّمَ اللهُ مُوسَى كَانَ نِدَاؤُهُ فِي السَّمَاءِ وَكَانَ اللهُ فِي السَّمَاءِ »',
  '« حتى يشهدوا أَن لاَّ إِلـه إلاَّ الله وأنِّي رَسُولُ الله »',
  '« إرحمُو من في الأرضِ يَرحَمُكُم من في السَّماء »',
  '« إرحمُو أهلَ الأرضِ يَرحَمُكُم أهلُ السَّماء »',
  '« وَقَالَ إِنِّي ذَاهِبٌ إِلَى رَبِّي سَيَهْدِينِ »',
  '« فَأَيْنَمَا تُوَلُّواْ فَثَمَّ وَجْهُ اللّهِ »',
  '« الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى »',
  '« قُلْ هَلْ يَسْتَوِي الَّذِينَ يَعْلَمُونَ وَالَّذِينَ لا يَعْلَمُونَ »',
  '« وما تقرّبَ إليَّ عبدي بشيءٍ أَحَبَّ إليَّ ممّا افترضتُ عليه »',
  '« لقد سألتَ عن عظيمٍ وإنه لَيسيرٌ على مَن يسّره اللهُ تعالى عليه تعبدُ اللهَ لا تُشرِكُ به شيئٌا وتُقيم الصلاةَ وتُؤتي الزكاةَ وتصومُ رمضانَ وتحُجُّ البيتَ إنِ استطعتَ إليه سبيلًا »',
  '« العبادة في الهَرْجِ كهِجْرةٍ إِلي »',
  'و في رواية قال : قال رسول الله صلى الله عليه وسلم : "يوشك أن يَحْسِرَ الفرات عن كنز من ذهب، فمن حضره فلا يأخذ منه شيئاً" متفق عليه (أي رَوَاهُ الْبُخَارِيُّ وَ مُسْلِمٌ)',
  'سَبْعَةٌ يُظِلُّهُمُ اللَّهُ فِي ظِلِّهِ يَوْمَ لاَ ظِلَّ إِلاَّ ظِلُّهُ',
  'ما مِنْ قَلْبٍ إِلا بَيْنَ إِصْبِعَيْنِ مِنْ أصَابِعِ الرَّحْمن إنْ شَاءَ أقَامَهُ وَإنْ شَاءَ أزَاغَهُ',
  '" يَنـزِلُ رَبُّنَا كُلَّ لَيْلَةٍ إِلَى السَّمَاءِ الدُّنْيَا "',
  'إن الله يمهل حتى يمضي شطر الليل الأول فيأمر مناديا فينادي …',
  '« يُنزِل ربٌّنا »',
  'وَمَنْ وَصَفَ اللهَ بِمَعْنًى مِنْ مَعَانِي البَشَر فَقَدْ كَفَر',
  '« اغتنم خمسا قبل خمسا اغتنم حياتك قبل موتك وصحتك قبل سقمك وشبابك قبل هرمك وغناك قبل فقرك وفراغك قبل شغلك »',
  'عن عائشة قالت : سألت رسول الله صلى الله عليه وسلم عن الالتفات في الصلاة فقال : « هو اختلاس (الأخذ بسرعة على غفلة) يختلسه الشيطان من صلاة العبد » رَوَاهُ البخاري',
  'عن أنس قال : قال لي رسول الله صلى الله عليه وسلم : « إياك والالتفات في الصلاة فإن الالتفات في الصلاة هلكة ، فإن كان لا بد ففي التطوع لا في الفريضة » رَوَاهُ الترمذي أي سبب الهلاك و ذلك لأن ارتكاب المكروهات قد يؤدي إلى ارتكاب المحرمات فيكون أهلك نفسه بتعريضها للعقاب',
  '« مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيا نَفَّسَ اللهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة، ومَنْ يَسَّرَ عَلى مُعْسِرٍ يَسَّرَ اللهُ عَلَيْهِ في الدُّنْيا والآخِرَةِ ومَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللهُ في الدُّنْيا والآخِرَةِ واللهُ في عَوْنِ العَبْدِ ما كانَ العَبْدُ في عَوْنِ أَخِيهِ ومَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللهُ بِهِ طَرِيقًا إِلى الجَنَّةِ وما اجْتَمَعَ قَوْمٌ في بَيْتٍ مِنْ بُيُوتِ اللهِ يَتْلُونَ كِتابَ اللهِ ويَتَدارَسُونَهُ بَيْنَهُمْ إِلاَّ نَزَلَتْ عَلَيْهِمُ السَّكِينَةُ وغَشِيَتْهُمُ الرَّحْمَةُ وحَفَّتْهُمُ الْمَلائِكَةُ وذَكَرَهُمُ اللهُ فِيمَنْ عِنْدَهُ ومَنْ بَطَّأَ بِهِ عَمَلُهُ لَمْ يُسْرِعْ بِهِ نَسَبُهُ »',
  '« مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيا نَفَّسَ اللهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة »',
  '« إِنَّما يَرْحَمُ اللهُ مِنْ عِبادِهِ الرُّحَماءَ »',
  '« إِنَّ اللهَ يُعَذِّبُ الَّذِينَ يُعَذِّبُونَ الناسَ في الدُّنْيا »',
  '« أَنَّ رَجُلاً مِنْ أَهْلِ الجَنَّةِ يُشْرِفُ يَوْمَ القِيامَةِ عَلى أَهْلِ النارِ، فَيُنادِيهِ رَجُلٌ مِنَ النارِ يا فُلانُ هَلْ تَعْرِفُنِي ؟ فَيَقُولُ لا واللهِ ما أَعْرِفُكَ مَنْ أَنْتَ ؟ فَيَقُولُ أَنا الَّذِي مَرَرْتَ بِهِ في دارِ الدُّنْيا فَٱسْتَسْقَيْتَنِي شُرْبَةً مِنْ ماءٍ فَسَقَيْتُكَ قالَ عَرَفْتُ. فَقالَ فَٱشْفَعْ لي بِها عِنْدَ رَبِّكَ، فَقالَ فَيَسْأَلُ اللهَ تَعالى فَيَقُولُ شَفِّعْنِي فِيهِ فَيُشَفَّعُ فِيهِ فَيَأْمُرُ بِهِ فَيُخْرَجُ مِنَ النار»',
  '« كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة »',
  '« يَعْرَقُ الناسُ يَوْمَ القِيامَةِ حَتَّى يَذْهَبَ عَرَقُهُمْ في الأَرْضِ سَبْعِينَ ذِراعًا، ويُلْجِمُهُمْ حَتَّى يَبْلُغَ ءاذانهم »',
  '« تُدْنَى الشَّمْسُ يَوْمَ القِيامَةِ مِنَ الخَلْقِ حَتَّى تَكُونَ مَنْهُمْ كَمِقْدارِ مِيلٍ فَيَكُونُ الناسُ عَلى قَدْرِ أَعْمالِهِمْ في العَرَقِ فَمِنْهُمْ مَنْ يَكُونُ إِلى كَعْبَيْهِ ومِنْهُمْ مَنْ يَكُونُ إِلى رُكْبَتَيْهِ ومِنْهُمْ مَنْ يَكُونُ إِلى حَقْوَيْهِ ومِنْهُمْ مَنْ يُلْجِمُهُ العَرَقُ إِلْجامًا »',
  '« كانَ تاجِرٌ يُدايِنُ الناسَ فَإِذا رَأَى مُعْسِرًا قالَ لِفِتْيانِهِ تَجاوَزُوا عَنْهُ لَعَلَّ اللهَ يَتَجاوَزُ عَنّا فَتَجاوَزَ اللهُ عَنْهُ »',
  '« ماتَ رَجُلٌ فَقِيلَ لَهُ بِمَ غَفَرَ اللهُ لَكَ ؟ فَقالَ كُنْتُ أُبايِعُ الناسَ فَأَتَجَوَّزُ عَنِ الْمُوسِرِ وأُخَفِّفُ عَنِ الْمُعْسِرِ »',
  '« مَنْ أَرادَ أَنْ تُسْتَجابَ دَعْوَتُهُ وأَنْ تُكْشَفَ كُرْبَتُهُ فَلْيُفَرِّجْ عَنْ مُعْسِرٍ »',
  '« وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللهُ في الدُّنْيا وَالآخِرَةِ »',
  '« وَاللهُ في عَوْنِ العَبْدِ ما كانَ العَبْدُ في عَوْنِ أَخِيهِ »',
  '« أَفْضَلُ الأَعْمالِ إِدْخالُ السُّرُورِ عَلَى الْمُؤْمِنِ، كَسَوْتَ عَوْرَتَهُ أَوْ أَشْبَعْتَ جَوْعَتَهُ أَوْ قَضَيْتَ حاجَتَهُ »',
  '« ومَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللهُ لَهُ بِهِ طَرِيقًا إِلى الجَنَّة »',
  '« ما جَلَسَ قَوْمٌ في بَيْتٍ مِنْ بُيُوتِ اللهِ يَتْلُونَ كِتابَ اللهِ ويَتَدارَسُونَهُ بَيْنَهُمْ إِلاَّ نَزَلَتْ عَلَيْهِمُ السَّكِينَةُ وغَشِيَتْهُمُ الرَّحْمَةُ وحَفَّتْهُمُ الْمَلائِكَةُ وذَكَرَهُمُ اللهُ فِيمَنْ عِنْدَهُ »',
  '« خَيْرُكُمْ مَنْ تَعَلَّمَ القُرْءانَ وعَلَّمَهُ »',
  '« ما مِنْ قَوْمٍ صَلُّوا صَلاةَ الغَداةِ ثُمَّ قَعَدُوا في مُصَلاّهُمْ يَتَعاطَوْنَ كِتابَ اللهِ ويَتَدارَسُونَهُ إِلاَّ وَكَّلَ اللهُ بِهِمْ مَلائِكَةً يَسْتَغْفِرُونَ لَهُمْ حَتَّى يَخُوضُوا في حَدِيثٍ غَيْرِهِ »',
  'ليس أمرًا عاديًا أن نرى طفلًا رضيعًا يتكلّم بكلام مفهم فصيح، ولكنَّ الله عزَّ وجلَّ يُظهِر بعض العجائب ليعتبر الناس ويتفكّروا ويتدبّروا، ومن هذه العجائب ما جرى مع إحدى الأمّهات التي كانت ترضع ولدها فحدثت أمامهما حادثة أخبرنا عنها النبيُّ الأعظم ﷺ وقد وقعت في إحدى الأمم السابقة.',
  'ثم سألت ولدها عن الشابّة التي كانت تُضرب فقال الطفل الرضيع: إن الشابّة كانت صالحة تقيّة، وقد افترى عليها بعض الناس زورًا وبهتانًا فصبرت وقالت: «حسبي الله ونعم الوكيل»، فدعوتُ الله أن يجعلني مثلها أي صابرًا محتسبًا، إن المغزى من هذه القصة أنّ بعض الناس قد يطلبون ما فيه مضرّتهم، والمطلوب ترك التكبّر والظلم كما أن المطلوب الصبر على الشدائد.',
  '« مَهْمَا تَصَوَّرْتَ بِباَلِكَ فَالله بِخِلافِ ذَالِك »',
  '« إِنَّ هَذا المالَ حُلْوَةٌ خَضِرَةٌ مَنْ أَخَذَهُ بِحَقِّهِ ووَضَعَهُ في حَقِّهِ فَنِعْمَ الْمَعُونَةُ هُوَ ومَنْ أَخَذَهُ بِغَيْرِ حَقِّهِ كانَ كَالَّذِي يَأْكُلُ ولا يَشْبَعُ »',
  '« نِعْمَ الْمالُ الصّالِحُ لِلرَّجُلِ الصّالِحِ »',
  '« ما نَفَعَنِي مالٌ قَطُّ ما نَفَعَنِي مالُ أَبِي بَكْرٍ »',
  '« مَا أَبْقَيْتَ لأَهْلِكَ »',
  'وَهَذَا لِسَانٌ عَرَبِيٌّ مُّبِينٌ',
  'لاَ يُقَالُ أَيْنَ لِمَنْ أَيَّنَ الأَيْنَ',
  '« إِذَا سَأَلْتَ فَاسْأَلِ اللهَ وَإِذَا اسْتَعَنْتَ فَاسْتَعِن باللهِ »',
  '« اللَّهُمَّ عَلِّمْهُ الحِكْمَةَ وَتَأْوِيلَ الكِتَابِ »'
);

-- douaa : 164 entrées
SELECT count(*) AS "douaa_a_supprimer" FROM "douaa" WHERE texte_arabe IN (
  '« إِذَا مَاتَ ابْنُ ءادَمَ انْقَطَعَ عَمَلُهُ إِلاَّ مِنْ ثَلاَثٍ صَدَقَةٍ جَارِيَةٍ وعِلْمٍ يُنْتَفَعُ بِهِ وَوَلَدٍ صَالِحٍ يَدْعُو لَهُ »',
  '« إِذَا مَاتَ ابْنُ ءادَمَ انْقَطَعَ عَمَلُهُ »',
  'الحمد لله رب العالمين',
  '« الدُعَاءُ هُوَ العِبَادَة »',
  'أَشْهَدُ أَنْ لاَ إلهَ إلاَّ اللَّهُ وَحْدَهُ لاَ شَرِيكَ لَهُ',
  'وَأَشْهَدُ أَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ',
  'لا إلهَ إلا اللهُ وَحْدَهُ لا شَرِيكَ لَهُ ، لَهُ المُلْكُ وَ لَهُ الحَمْدُ',
  'يُحْيِي وَ يُمِيتُ وَهُوَ عَلَى كُلِّ شيء قَدِير',
  'اللَّهُمَّ أعِنِّي على ذِكْرِكَ وَشُكْرِكَ وحُسْنِ عِبادَتِكَ',
  'اللَّهُمَ أَنْتَ السَّلام وَمِنْكَ السَّلام تَبَارَكْتَ يَا ذَا الجَلالِ وَالإكْرَام',
  'مَنْ سَبَّحَ اللَّهَ فِي دُبُرِ كُلِّ صَلاةٍ ثَلاثًا وَثَلاثِينَ وَحَمِدَ اللَّهَ ثَلاثًا وَثَلاثِينَ وَكَبَّرَ اللَّهَ ثَلاثًا وَثَلاثِينَ فَتْلِكَ تِسْعَةٌ وَتِسْعُونَ وَقَالَ تَمَامَ الْمِائَةِ : لا إِلَهَ إِلاّ اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ غُفِرَتْ خَطَايَاهُ وَإِنْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ',
  'اللَّهُمَّ أجِرْنِي مِنَ النَّارِ',
  'إِنَّ النَّاسَ إِذا اجْتَمَعُوا فِي مَجْلِس ثُمَّ فَارَقُوهُ وَلَمْ يَذْكُرُوا اللهَ',
  'وَلَمْ يُصَلُّوا عَلَى النَّبِي يَكُونُ حَسْرَةً عَلَيْهِم فِي الآخِرَةِ وَإِن دَخَلُوا الجَنَّة',
  'لاَ إِلهَ إِلاَّ اللّه',
  'اللَّهُمَّ صَلِّ عَلَى سَيِّدِنَا مُحَمَّدٍ وَ عَلَى آلِهِ وَ صَحْبِهِ وَ سَلِّم',
  'ربِّ اغْفِرْ لِي وَلِلْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ',
  'بِاسْمِ اللهِ',
  'بِسمِ اللَّه، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الخُبْثِ وَالخَبَائِث',
  'الحَمدُ لِلَّهِ الَّذِي أَذهَبَ عَنِّي الأَذَى وَعَافَانِي',
  'اللَّهُمَّ بَارِك لَنَا فِيْمَا رَزَقْتَنَا وَ قِنَا عَذَابَ النَّار',
  'بِسْمِ الله',
  'بِسْمِ اللهِ أَوَّلَهُ وَآخِرَه',
  'الحَمْدُ للهِ الذِي أطْعَمَنَا وَسَقَانَا وَجَعَلَنَا مُسْلِمِيْن',
  '« اللَّهُمَّ إِنّي أَسْأَلُكَ وأَتَوَجَّهُ إِلَيكَ بِنَبِيِّكَ مُحَمَّدٍ نَبِيِّ الرَّحْمَةِ. يا مُحَمَّدُ إِنِّي أَتَوَجَّهُ بِكَ إِلى رَبِّي فِي حَاجَتِي لِتُقْضَى لِي »',
  'اللَّهُمَّ إنِّي أسْتَوْدِعُكَ هَذَا المَكَانَ وَ مَا فِيهِ وَ مَنْ فِيه',
  'أَعُوذُ بِوَجْهِ اللَّهِ الْعَظِيمِ الَّذِي لَيْسَ شَيْءٌ أَعْظَمَ مِنْهُ وَبِكَلِمَاتِ اللَّهِ التَّامَّاتِ الَّتِي لَا يُجَاوِزُهُنَّ بَرٌّ وَلَا فَاجِرٌ وَبِأَسْمَاءِ اللَّهِ الْحُسْنَى مَا عَلِمْتُ مِنْهَا وَمَا لَمْ أَعْلَمْ مِنْ شَرِّ مَا خَلَقَ وَذَرَأَ وَبَرَأَ',
  'أعوذُ بكلماتِ اللهِ التّامّة مِن كُلّ شَيطانٍ وهامّةٍ ومن كُلّ عَينٍ لامّةٍ',
  'اللّهُم ذا السُّلطانِ العَظيمِ والمَنِّ القديمِ، ذا الرّحمةِ الكريم وليَّ الكلماتِ التّامّاتِ والدَّعوات المُستَجابات عافِني من أنفس الجنِّ وأعْيُنِ الإنسِ.',
  'اللهمَّ ذَا السلطانِ العظيمِ والْمَنِّ القديـمِ ذَا الرحـمةِ الكريـم',
  'وَلِيَّ الكلماتِ التَّاماتِ والدَّعواتِ المستجاباتِ',
  'عافِ حَسنًا وحُسينًا من أنفسِ الجِنِّ وأَعيُنِ الإنسِ',
  'اللهُمَّ إنِّي أعُوذُ بِكَ مِنَ الهَمِّ والحَزَن وأعُوذُ بِكَ مِنَ العَجْزِ والكَسَل وأعُوذُ بِكَ مِنَ الجُبْنِ والبُخْلِ وأعُوذُ بِكَ من غَلبَةِ الدَّينِ وقَهْرِ الرِّجَالِ. (لقضاء الدّين)',
  'وَجَّهْتُ وَجْهِيَ لِلَّذِي فَطَرَ السَّموَاتِ وَالأَرْضَ',
  'حَنِيفاً مُسْلِماً وَمَا أَنَا مِنَ الْمُشْرِكِينَ',
  'إنَّ صَلاَتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ العَالَمِينَ لاَ شَرِيكَ لَهُ',
  'وَبِذَلِكَ أُمِرْتُ وَأَنَا مِنَ الْمُسْلِمِينَ',
  'التَّحِيَّاتُ المُبَارَكَاتُ الصَّلَوَاتُ الطَّيِّبَاتُ لِلّه',
  'السَّلاَمُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللهِ وَبَرَكَاتُهُ',
  'السَّلاَمُ عَلَيْنَا وَعَلَى عِبَادِ اللهِ الصَّالِحِينَ',
  'أَشْهَدُ أَن لاَ إِلهَ إِلاَّ اللهُ وَأَشْهَدُ أَنَّ مُحَمَّداً رَسُولُ الله',
  'اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ',
  'كَمَا صَلَّيْتَ عَلَى إبْرَاهِيمَ وَعَلَى آلِ إبْرَاهِيمَ',
  'إنَّكَ حَمِيدٌ مَجِيدٌ',
  'اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ',
  'كَمَا بَارَكْتَ عَلَى إبْرَاهِيمَ وَعَلَى آلِ إبْرَاهِيمَ',
  'قَالَ رَسُولُ اللَّهِ ﷺ: « إِذَا فَرَغَ أَحَدُكُمْ مِنَ التَّشَهُدِ الآخِرِ فَلْيَتَعَوَّذْ بِاللَّهِ مِنْ أَرْبَعٍ: مِنْ عَذَابِ جَهَنَّمَ، وَمِنْ عَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ، وَمِنْ شَرِّ الْمَسِيحِ الدَّجَّالِ »',
  '« اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ، وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ، وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْمَأْثَمِ وَالْمَغْرَمِ »',
  '« اللَّهُمَّ اغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ، وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ، وَمَا أَسْرَفْتُ وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي، أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لا إِلهَ إِلا أَنْتَ »',
  '« قُلْ اللَّهُمَّ إِنِّي ظَلَمْتُ نَفْسِي ظُلْمًا كَثِيرًا وَلا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ، فَاغْفِرْ لِي مَغْفِرَةً مِنْ عِنْدِكَ وَارْحَمْنِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ »',
  '« لا إِلهَ إِلا اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَىءٍ قَدِيرٌ. اللَّهُمَّ لا مَانِعَ لِمَا أَعْطَيْتَ، وَلا مُعْطِيَ لِمَا مَنَعْتَ، وَلا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ »',
  '« لا إِلهَ إِلا اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَىءٍ قَدِيرٌ، لا حَوْلَ وَلا قُوَّةَ إِلا بِاللَّهِ، لا إِلهَ إِلا اللَّهُ وَلا نَعْبُدُ إِلا إِيَّاهُ، لَهُ النِّعْمَةُ وَالْفَضْلُ، وَلَهُ الثَّنَاءُ الْحَسَنُ، لا إِلهَ إِلا اللَّهُ مُخْلِصِينَ لَهُ الدِّينَ وَلَوْ كَرِهَ الْكَافِرُونَ »',
  '« مُعَقِّبَاتٌ لا يَخِيبُ قَائِلُهُنَّ أَوْ فَاعِلُهُنَّ دُبُرَ كُلِّ صَلاةٍ مَكْتُوبَةٍ ثَلاثًا وَثَلاثِينَ تَسْبِيحَةً، وَثَلاثًا وَثَلاثِينَ تَحْمِيدَةً، وَثَلاثًا وَثَلاثِينَ تَكْبِيرَةً »',
  'وَفِي حَدِيثٍ ءَاخَرَ لِمُسْلِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ رَسُولِ اللَّهِ ﷺ أَنَّ مَنْ فَعَلَ ذَلِكَ وَقَالَ تَمَامَ الْمِائَةِ: « لا إِلهَ إِلا اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَىءٍ قَدِيرٌ غُفِرَتْ ذُنُوبُهُ وَإِنْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ »',
  'وَرَوَى الْبُخَارِيُّ فِي الصَّحِيحِ عَنْ سَعْدِ بنِ أَبِي وَقَّاصٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ رَسُولَ اللَّهِ ﷺ كَانَ يَتَعَوَّذُ دُبُرَ الصَّلاةِ بِهَؤُلاءِ الْكَلِمَاتِ: « اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْجُبْنِ، وَأَعُوذُ بِكَ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ، وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا، وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ »',
  'يَا مُعَاذُ وَاللَّهِ إِنِّي لأُحِبُّكَ ثُمَّ قَالَ: « أُوصِيكَ يَا مُعَاذُ لا تَدَعَنَّ فِي دُبُرِ كُلِّ صَلاةٍ أَنْ تَقُولَ: اللَّهُمَّ أَعِنِّي عَلَى ذِكْرِكَ وَشُكْرِكَ وَحُسْنِ عِبَادَتِكَ »',
  '« اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْكُفْرِ وَالْفَقْرِ وَعَذَابِ الْقَبْرِ »',
  '« اللَّهُمَّ اغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي، أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لا إِلهَ إِلا أَنْتَ »',
  '« إن من أفضل أيامكم يوم الجمعة فأكثروا عليّ من الصلاة فيه فإن صلاتكم معروضة علي »',
  '« مَنْ صلّى عليَّ عَصْرَ يومِ الجُمُعَةِ ثمانينَ مرّةً غَفَرَ اللهُ لهُ ذنوبَ ثمانينَ عامًا »',
  '« تقول: اللهم صل على محمد عبدك ونبيك ورسولك النبي الأمي وتعقد واحدة »',
  'اللَّهُمَّ إنَّهُ بَلَغَنِي أَنَّ نَبِيَّكَ قَالَ مَاءُ زَمْزَمَ لِمَا شُرِبَ لَه',
  'اللَّهُمَّ إِنِّي أَشْرَبُهُ مُسْتَشْفِيًا بِهِ فَاشْفِنِي وَاغْفِرْ لِي',
  'اللَّهُمَّ إِنِّي أَسْأَلُكَ عِلْمًا نَافِعًا وَرِزْقًا وَاسِعًا وَشِفَاء مِنْ كُلِّ دَاء',
  '« بِاسْمِ اللهِ، اللَّهُمَّ اِفْتَحْ لِـي أَبْوَابَ رَحْـمَتِكَ وَانْشُرْ عَلَيَّ خَزَائِنَ عِلْمِكَ »',
  'اللَّهُمَّ صَلِّ على سَيّدِنَا مُحمَّدٍ صَلَّى اللهُ عَلَيْهِ وسَلَّم اللَّهُمَّ افْتَحْ لي أبْوابَ رَحْمَتِكَ',
  '« مَنْ قَالَ فِي سُوقٍ مَنْ هَذِهِ الأَسْوَاقِ لا إِلهَ إِلا اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيِي وَيُمِيتُ وَهُوَ حَيٌّ لا يَمُوتُ بِيَدِهِ الْخَيْرُ وَهُوَ عَلَى كُلِّ شَىءٍ قَدِيرٌ، كَتَبَ اللَّهُ عَزَّ وَجَلَّ لَهُ أَلْفَ أَلْفِ حَسَنَةٍ، وَمَحَا عَنْهُ أَلْفَ أَلْفِ سَيِّئَةٍ، وَبَنَى لَهُ بَيْتًا فِي الْجَنَّةِ »',
  'باركَ اللَّهُ لكَ',
  'باركَ اللَّهُ عليكَ وجَمعَ بينكما في خير',
  'باركَ اللَّهُ لكُلِّ واحدٍ منكُما في صاحِبهِ وجَمَعَ بينكما في خير',
  '« بَارَكَ اللَّهُ لَكَ وَبَارَكَ عَلَيْكَ وَجَمَعَ بَيْنَكُمَا فِي خَيْرٍ »',
  '« أسألك من خيرها و خير ما جبلت عليه وأعوذ بك من شرّها و شرّ ما جبلت عليه »',
  'الحَمْدُ لله',
  'يَرْحَمُكَ الله',
  'يَهْدِيكُمُ الله ويُصْلِحُ بَالَكُم',
  'اللَّهُمَّ لا سَهْلَ إلاّ مَا جَعَلْتَهُ سَهْلا وَإِنَّكَ تَجْعَلُ الحَزْنَ إِذَا شِئْتَ سَهْلا',
  'بسم الله، ربّي الله، حسبي الله، توكّلت على الله، اعتصمت بالله، فوّضت أمري إلى الله، ما شاء الله، لا قوّة إلاّ بالله',
  'اللهم صلِّ صلاةً كاملةً، وسلِّم سلامًا تامًّا على سيِّدنا محمّد، الذي تَنحَلُّ به العُقد وتَنفَرجُ به الكُرَب، وتُقضى به الحوائجُ، وتُنالُ به الرَّغائِب وحُسنُ الخَواتيم، ويُستسقى الغَمام بوجهِه الكَريم، وعلى ءاله وصحبه وسلِّم.',
  'فضل هذه الصيغة: تسمى هذه الصيغة في الصلاة على النبيّ بـ "الصلاة النارية" وتقال: [4444] مرة لقضاء الحاجة. أو [100] مرة لرؤية الرسول الأعظم صلى الله عليه وسلم',
  '« اللَّهُمَّ رَبَّ النَّاسِ، أَذْهِبِ البَأْسَ، اِشْفِ أَنْتَ الشَّافِـي، لاَ شِفَاءَ إِلاَّ شِفَاءُكَ »',
  'باِسْمِ اللهِ، بِاسْمِ اللهِ، بِاسْمِ اللهِ',
  'أعُوذُ بِعِزَّةِ اللهِ وَقُدْرَتِهِ مِنْ شَرِّ ما أجِدُ وأُحاذِرُ (للشّفاء، 7 مرّات)',
  'بِسْمِ اللهِ أَرْقِيكَ مِنْ كُلِّ شَىءٍ يُؤذِيكَ مِنْ شَرِّ كُلِّ نَفْسٍ أَو عَيْنِ حَاسِدٍ',
  'اللهُ يَشْفِيكَ بِسْمِ اللهِ أَرْقِيك',
  'الـحَمْدُ للهِ الَّذِي كَسَانِـي مَا أُوَارِي بِهِ عَوْرَتـِي وأَتَـجَمَّلُ بِهِ فِي حَيَاتِـي',
  'اللَّهُمَّ غَارَتِ النُّجُومُ وَهَدَأَتِ الْعُيُونُ وَأَنْتَ حَيٌّ قَيُّومٌ',
  'لا تَأْخُذُكَ سِنَةٌ وَلا نَوْمٌ ، يَا حَيُّ يَا قَيُّومُ أَهْدِئْ لَيْلِي وَأَنِمْ عَيْنِي',
  'الحَمْدُ لله اللَّهمَّ كما حَسَّنْتَ خَلْقِي فَحَسِّنْ خُلُقِي',
  'الـحَمْدُ للهِ الَّذِي خَلَقَنِـي فَسَوَّانِـي، اللَّهُمَّ كَمَا حَسَّنْتَ خَلْقِي فَحَسِّنْ خُلُقِي',
  '« اللَّهُمَّ أَدْخِلْهُ عَلَيْنَا بِالْأَمْنِ وَالْإِيمَانِ، وَالسَّلَامَةِ وَالْإِسْلَامِ، وَرِضْوَانٍ مِنَ الرَّحْمَنِ، وَجِوَارٍ (أيْ حِفْظٍ) مِنَ الشَّيْطَانِ »',
  'بِسْمِ الإلــــٰهِ وَبِهِ بَدَيْنَا وَلَوْ عَبَـدْنا غَيْرَهُ شَـقِينَا وَحَبـَّذَا رَبـًّا وَحَبَّ دِينــا وَحَبَّذَا مُـحَمَّدٌ هَادِينَا',
  '{سُبْحَانَ رَبِّكَ رَبِّ الْعِزَّةِ عَمَّا يَصِفُونَ (180) وَسَلَامٌ عَلَى الْمُرْسَلِينَ (181) وَالْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ (182)} [سورة الصافات 180 - 182]',
  'اللَّهُمَّ رَادَّ الضَّالَّةِ، وَهَادِيَ الضَّلَالَةِ تَهْدِي مِنَ الضَّلَالَةِ، ارْدُدْ عَلَيَّ ضَالَّتِي بِقُدْرَتِكِ وَسُلْطَانِكَ، فَإِنَّهَا مِنْ عَطَائِكَ وَفَضْلِكَ',
  'يا جامعَ النَّاسِ ليومٍ لا ريبَ فيه اجمعْ عَلَيَّ ضَالَّتِي',
  'اللَّهُمَّ رَادَّ الضَّالَّةِ، هَادِيَ الضَّالَّةِ، تَهْدِي مِنَ الضَّلَالَةِ، رُدَّ عَلَيَّ ضَالَّتِي، بِعِزَّتِكَ وَسُلْطَانِكَ، فَإِنَّهَا مِنْ فَضْلِكَ وَعَطَائِكَ',
  'سورة الفاتحة (3 مرات)',
