  'سَلَامٌ قَوْلًا مِّن رَّبٍّ رَّحِيمٍ (21 مرات)',
  'رَبَّنَا آتِنَا مِن لَّدُنكَ رَحْمَةً وَهَيِّئْ لَنَا مِنْ أَمْرِنَا رَشَدًا (21 مرات)',
  'لا إله إلا الله (121 مرات)',
  'لفظ الجلالة الله (121 مرات)',
  'الصَّلاةُ وَالسَّلامُ عَلَيكَ يَا سَيِّدِي يَا رَسُولَ اللهَ يَا أَحْمَد قَلَّتْ حِيلَتِي وَأَنتَ وَسِيلَتِي فَأَدْرِكْنِي (21 مرات)',
  'يَا عِبَادَ الله أغِيثُونَا (3 مرات)',
  'اللّهُم أَمِدَّنَا بِأمدَادِ السَّيِّد أَحمَد الرِّفَاعِيِّ (3 مرات)',
  'الفاتحة على النية (مرة واحدة)',
  '« لَوْ أَنَّ أَحَدَكُمْ إِذَا أَتَى أَهْلَهُ قَالَ : بِسْمِ اللَّه ، اللَّهُمَّ جَنِّبْنَا الشَّيْطَانَ ، وَجَنِّب الشَّيْطَانَ مَا رَزَقْتَنَا ، فَقُضِيَ بَيْنَهُمَا وَلَدٌ لَمْ يَضُرَّهُ »',
  '« لَمْ يَضُرَّهُ شَيْطَانٌ أَبَداً »',
  'اللهُمَّ أنْتَ رَبِّي لا إلهَ إلا أنْتَ خَلَقْتَنِي وَأنَا عَبْدُكَ وَأنَا عَلَى عَهْدِكَ وَوَعْدِكَ ما اسْتَطَعْتُ أعُوْذُ بِكَ مِن شَرِّ مَا صَنَعْتُ أبُوْءُ لَكَ بِنِعْمَتِكَ عَلَيَّ وَأبُوْءُ بِذَنْبِي فَاغْفِرْ لِي فَإنَّهُ لا يَغْفِرُ الذُّنُوبَ إلا أنْتَ',
  'رَبِّ اغْفِرْ لِي وَلِوَالِدَيَّ وَارْحَمْهُمَا كَمَا رَبَّيانِي صَغِيرا',
  'اللهم اجعله صَيِّبًا هنيئا',
  'اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ وَأَسْتَقْدِرُكَ بِقُدْرَتِكَ وَأَسْأَلُكَ مِنْ فَضْلِكَ فَإِنَّكَ تَعْلَمُ وَلَا أَعْلَمُ وَتَقْدِرُ وَلَا أَقْدِرُ وَأَنْتَ عَلَّامُ الغُيُوب اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الأَمْرَ خَيْرٌ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ فِي عَاجِلِ أَمْرِي وَءَاجِلِه فَاقْدِرْهُ لِي وَيَسِّرْهُ لِي وَإِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الأَمْرَ شَرٌّ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ فِي عَاجِلِ أَمْرِي وَءَاجِلِه فَاصْرِفْهُ عَنِّي وَاصْرِفْنِي عَنْهُ وَاقْدِرْ لِي الخَيْرَ حَيْثُ كَانَ وَرَضِّنِي بِهِ',
  'رَبَّنا ءاتِنا فِي الدُّنيا حَسَنَةً وفِي الآخِرَةِ حَسَنَةً، وقِنَا عَذَابَ النَّار',
  'بَارَكَ اللَّهُ فِيكَ',
  'أَحْسَنَ اللَّهُ إلَيْكَ',
  'جَزَاكَ اللَّهُ خَيْراً',
  'بِاسْمِ اللَّه، اللَّهُمَّ إِنّىِ أَسْأَلُكَ خيْر المَوْلَجِ وَخَيْرَ الْمَخْرَجِ، بِاسْمِ اللَّهِ وَلَجْنا، وَبِاسْمِ اللَّهِ خَرَجْنا، وَعَلَى اللَّهِ رَبِنا تَوَكَّلْنا',
  'الحَمْدُللهِ الذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَ إِلَيْهِ النُّشُور',
  'اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ النَّبِيِّ وَأَزْوَاجِهِ أُمَّهَاتِ الْمُؤْمِنِينَ وَذُرِّيَّتِهِ وَأَهْلِ بَيْتِهِ كَمَا صَلَّيْتَ عَلَى ءَالِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ',
  'اللَّهُمَّ لَكَ صُمْت وَعَلَى رِزْقِكَ أَفْطَرْت',
  'سُبحَانَ الله وَبِحمدِهِ هِيَ سَببٌ لِتَيسيرِ الرِّزقِ، الَّذِي يُكثِرُ من سُبحَانَ الله وَبِحمدِهِ اللهُ تَعَالَى يُيَسِرُ لَهُ بَابَ الرِّزقِ، مَنَافِعُهَا عَظِيمَةٌ.',
  'لا إله إلا اللهُ الملِكُ الحَقُّ المُبين',
  'لتَيْسِير الرِّزْقِ مِائَة مَرّة (يا وَهَّاب) بعدَ صَلاة الضُّحَى.',
  'لتَيْسِير الرِّزْقِ (سُورَة الواقِعَة) بعدَ صَلاة المغرب.',
  'كتابة البسملة خَمسًا وثلاثين مرة لتيسير الرزق يوضع على باب الدكان لرواج البضاعة. (تُكتَبُ البَسمَلَة خمسًا وثَلاثِينَ مَرّةً وتُحمَلُ أو تُعَلَّقُ على بابِ البَيتِ أو الدُّكّان لتَيسِير الرّزْقِ فيهَا سِرٌّ عَظِيم).',
  'وَرَدَ في الحَديث القُدسيّ: "يَا دُنيَا مَن خَدَمَنِي فَاخْدُمِيْهِ ومَن خَدَمَكِ فأَتْعِبِيْه". ومعناه: اللهُ تعالى يُيَسّر الرّزقَ لمن اتّقَى الله واشْتَغَل بطَاعَتِه. ومَعنى "خَدَمَني" في هذا الحديث: أطَاعَني.',
  'عن سَلّام بنِ شُرَحْبِيْلَ عن حَبَّةَ وسَوَاء ابنَي خَالدٍ رَضيَ اللهُ تَعالى عنهُما قَالا أَتَينَا رَسولَ الله صلى الله عليه وسلم فقال : "لَا تَيْئَسَا مِنَ الرّزْقِ مَا تَهَزْهَزَت رُؤوسُكُما فإنّ الإنسَانَ تَلِدُه أُمُّهُ أَحمرَ لا قِشْرَ عَلَيهِ ثم يَرزُقُهُ اللهُ عَزَّ وَجَلّ". هذا حَديثٌ صَحِيحٌ أخرَجَه أَحمَد.',
  'ورَد حديثٌ صَحيح: "مَنْ لَزِمَ الاستِغفَارَ جَعَلَ اللهُ لهُ مِن كُلّ ضِيقٍ مَخرَجًا ومِن كُلّ هَمّ فَرَجًا ورَزقَه مِن حَيثُ لا يَحتَسِب" رواه أبو داود ، وابن ماجه ، والبيهقى عن ابن عباس ورواه أبو داود والطبراني)',
  'لمن يَشكُو الضّيقَ مِن حيث المال أكثِر مِن الاستغفار، استَغفِر الله كلَّ يَوم ثَلاثمائة مَرّة.',
  'مَنْ قَرَأَ هَذَا الدُّعاءَ فِي اليَوْمِ عِشْرِيْنَ مَرَّةً لَم يَرَ قِلَّةً أَبَدًا، وَهُوَ مُجَرَّبٌ صَحِيْحٌ : "بِسْمِ اللهِ الرَّحمنِ الرَّحِيمِ، يَا عَظِيمَ الجَلَالِ، يَا بَدِيعَ الكَمَالِ، يَا كَثِيْرَ النَّوَالِ، يَا دَائِمَ الإِفْضَالِ، يَا حَسَنَ الفَعَالِ، يَا قَائِمُ بِلَا زَوَالٍ، وَصَلَّى اللهُ عَلَى سَيِّدِنَا مُحَمَّدٍ وَعَلَى ءَالِهِ وَصَحْبِهِ وَسَلَّم"',
  'شَخصٍ لم يُرزَق أَولادًا مُنذُ عَشرِ سنِينَ : لِيُكثِرُوا مِنَ الاستِغفَار، ليَلزَم. شَخصٌ لَزِمَ الاستِغفَارَ فرُزِقَ.',
  'وَرَدَ حَدِيثٌ بِإِسْنَادٍ ضَعِيفٌ: "الصُّبْحَةُ تَمْنَعُ الرِّزْقَ"، الصُّبْحَةُ فَمَعْنَاهُ النَّوْمُ بَعْدَ صَلَاةِ الصُّبْحِ (أي أوَّلَ النَّهَارِ)، لَكِنَّهُ إِنْ كَانَ الشَّخْصُ يَنَامُ بِلَا فَائِدَةٍ (هذَا الذِي نَقُولُ) لَا خَيْرَ فِيهِ (لأنَّهُ قَد يَكُونُ نَوْمُهُ لِمَرَضٍ).',
  'بِسْمِ الله ، تَوَكَّلْتُ عَلَى الله ، وَلا حَوْلَ وَلا قُوَّةَ إلا بِالله',
  'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ أَنْ أَضِلَّ أَو أُضَلَّ أَو أَزِلَّ أَو أُزَلَّ، أَو أَظْلِمَ أَو أُظْلَمَ، أَو أَجْهَلَ أَو يُجْهَلَ عَلَيَّ',
  'اللَّهُمَّ صَلِّ عَلَى سَيِّدِنَا مُحَمَّدٍ صَلَّى اللهُ عَلَيْهِ وسَلَّم. اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ',
  '« لـمّا اقترف آدمُ الخطيئة قال : يا ربّ أسألك بحق محمد إلا ما غفرت لي »',
  'سُبْحَانَ الذِي يُسَبِّحُ الرَعْدُ بِحَمْدِهِ وَالمَلائِكَةُ مِنْ خِيفَتِه',
  'اللهُ أكْبَر اللهُ أكْبَر اللهُ أكْبَر سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَٰذَا',
  'وَمَا كُنَّا لَهُ مُقْرِنِينَ وَ إنَّا إلى رَبِّنَا لَمُنْقَلِبُوْن',
  'أسألُ اللهَ العظيمَ ربَّ العرشِ العظيمِ أنْ يشفيَك',
  'أَسْتَوْدِعُكَ اللهَ الَّذِي لاَ تَضِيعُ وَدَائِعُهُ',
  'أستَودِعُ اللَّهَ دِينَكَ وَأَمَانَتَكَ وَخَوَاتِيمَ عَمَلِكَ',
  'اللهُ أكْبَر، اللهُ أكْبَر، اللهُ أكْبَر، اللَّهُمَّ إِنَّا نَسْأَلُكَ في سَفَرِنَا هذا البِرَّ والتَّقوى ومِنَ العَمَلِ ما تَرْضى، اللَّهُمَّ هَوِّنْ علَيْنا سفَرَنَا هذا وَاطْوِ عنَّا بُعْدَهُ، اللَّهُمَّ أَنتَ الصَّاحِبُ في السَّفَرِ وَالخَلِيفَةُ في الأهْلِ، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وعْثَاءِ السَّفَرِ، وكآبةِ المَنظَرِ، وَسُوءِ المُنْقلَبِ في المالِ والأهلِ',
  'نطق الفؤاد وبالغرام أجابكم أنا مذهبي عن حبّكم لا أذهب',
  'الله عظَّمَ قَدْرَ محمّدٍ وأَنالهُ فضلًا لديهِ عظيمًا في مُحكَمِ التَنزيلِ قال لِخلقِهِ صَلُّوا عليهِ وسَلّموا تَسليمًا',
  '« مَنْ صَلَّى عَلَيَّ مِنْ أُمَّتِي صَلاةً مُخْلِصًا مِنْ قَلْبِهِ صَلَّى اللهُ عَلَيْهِ بِها عَشْرَ صَلَواتٍ ورَفَعَهُ بِها عَشْرَ دَرَجاتٍ وكَتَبَ لَهُ بِها عَشْرَ حَسَناتٍ ومَحَا عَنْهُ عَشْرَ سَيِّئاتٍ »',
  '« صَلُّوا عَلَيَّ فَإِنَّها زَكاةٌ لَكُمْ وٱسْأَلُوا اللهَ لِي الوَسِيلَةَ فَإِنَّها دَرَجَةٌ في أَعْلَى الجَنَّةِ لا يَنالُها إِلَّا رَجُلٌ وأَرْجُو أَنْ أَكُونَ أَنا هُوَ »',
  '« إِذا سَمِعْتُمُ الْمُؤَذِّنَ فَقُولُوا مِثْلَ ما يَقُولُ ثُمَّ صَلُّوا عَلَيَّ فَإِنَّهُ مَنْ صَلَّى عَلَيَّ صَلاةً صَلَّى اللهُ عَلَيْهِ بِها عَشْرًا ثُمَّ سَلُوا اللهَ لِي الوَسِيلَةَ فَإِنَّها مَنْزِلَةٌ في الجَنَّةِ لا تَنْبَغِي إِلَّا لِعَبْدٍ مِنْ عِبادِ اللهِ وأَرْجُو أَنْ أَكُونَ أَنا هُوَ فَمَنْ سَأَلَ لِي الوَسِيلَةَ حَلَّتْ لَهُ الشَّفاعَةُ »',
  '« إِنَّ أَوْلَى الناسِ بِي يَوْمَ القِيامَةِ أَكْثَرُهُمْ عَلَيَّ صَلاةً »',
  '« اللهُ يَعْلَمُ إِنِّي لَأُحِبُّكُنَّ »',
  '« يغفر ذنبًا ويكشف كربًا ويرفع قومًا ويضع آخرين »',
  '« سُبحان الّذي يُغَيّر ولا يتغيَّر »',
  '« لَا يَرُدُّ القَضَاءَ إِلّا الدُّعَاءُ »',
  '« إنَّ النّذرَ لا يَرُدُّ منْ قدَرِ اللهِ وإِنّمَا يُستَخْرَجُ بِهِ مِنَ البَخيلِ »',
  '« سألت ربي أربعًا فأعطاني ثلاثًا ومنعني واحدة : سألته أن لا يُكْفِرَ أمتي جملة فأعطانيها وسألته أن لا يهلكهم بما أهلك به الأمم قبلهم فأعطانيها، وسألته أن لا يظهر عليهم عدوًا من غيرهم فيستأصلهم فأعطانيها، وسألته أن لا يجعل بأسهم بينهم فمنعنيها »',
  '« سألت ربي ثلاثًا فأعطاني ثنتين ومنعني واحدة »',
  '« قال لي يا محمد إني إذا قضيت قضاء فإنه لا يرد »',
  'اللّهمّ يا الله يا الله يا الله يا حيّ يا قيّوم يا غفور يا توّاب يا فتّاح يا رزّاق يا واسع يا معين يا باسط يا مبدئ يا وهّاب يا متين ويا حافظ يا وليّ يا كافي يا حسيب يا أرحم الرّاحمين يا ذا المنّ ويا ذا الفضل ويا ذا الجلال والإكرام ويا ذا الطّول والإنعام ويا من تمحو ما تشاء وتثبت ما تشاء ويا من عندك أمّ الكتاب بحقّ أسماءك الحسنى وآياتك العظمى وبحقّ اسمك العظيم الأعظم وبالتجلّي في ليلة النّصف من شعبان المكرّم صلّ على سيّدنا ومولانا وحبيبنا وشفيعنا وملاذنا محمّد رسولك ونبيّك الأكرم صلاة كاملة دائمة تكتبنا بها عندك في هذه اللّيلة المباركة مغفورين لهم مسعودين معمّرين بالخير مرزوقين موفّقين للأذكار والطّاعات والخيرات والحسنات ومستغنين بفضلك في الدّارين عمّن سواك وصلّ على سيّدنا محمّد صلاة تكتبنا بها في هذه اللّيلة من السّعداء والصّالحين وترزقنا بها في الدّارين إيمانا كاملا وكمال اليقين بحقّ سيّدنا محمّد سيّد المرسلين وإمام المتّقين ومحبوب ربّ العالمين وتكشف بها عنا البليات والآفات والعاهات الواردة بإرادتك هذه السّنة لتصيب بها من تشاء من عبادك إنّك مجيب الدّعوات وما ذلك على الله بعزيز وصلّى الله على سيّدنا محمّد وعلى آله وصحبه وسلّم.',
  '« إِذَا سَمِعْتُمُ المُؤَذِّنَ فَقُولُوا كَمَا يَقُولُ ثُمَّ صَلُّوا عَلَيَّ »',
  '« مَن ذَكَرَنِي فَلْيُصَلِّ عَلَيَّ »'
);

DELETE FROM "douaa" WHERE texte_arabe IN (
  '« إِذَا مَاتَ ابْنُ ءادَمَ انْقَطَعَ عَمَلُهُ إِلاَّ مِنْ ثَلاَثٍ صَدَقَةٍ جَارِيَةٍ وعِلْمٍ يُنْتَفَعُ بِهِ وَوَلَدٍ صَالِحٍ يَدْعُو لَهُ »',
  '« إِذَا مَاتَ ابْنُ ءادَمَ انْقَطَعَ عَمَلُهُ »',
  'الحمد لله رب العالمين',
  '« الدُعَاءُ هُوَ العِبَادَة »',
  'أَشْهَدُ أَنْ لاَ إلهَ إلاَّ اللَّهُ وَحْدَهُ لاَ شَرِيكَ لَهُ',
  'وَأَشْهَدُ أَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ',
  'لا إلهَ إلا اللهُ وَحْدَهُ لا شَرِيكَ لَهُ ، لَهُ المُلْكُ وَ لَهُ الحَمْدُ',
  'يُحْيِي وَ يُمِيتُ وَهُوَ عَلَى كُلِّ شيء قَدِير',
  'اللَّهُمَّ أعِنِّي على ذِكْرِكَ وَشُكْرِكَ وحُسْنِ عِبادَتِكَ',
  'اللَّهُمَ أَنْتَ السَّلام وَمِنْكَ السَّلام تَبَارَكْتَ يَا ذَا الجَلالِ وَالإكْرَام',
  'مَنْ سَبَّحَ اللَّهَ فِي دُبُرِ كُلِّ صَلاةٍ ثَلاثًا وَثَلاثِينَ وَحَمِدَ اللَّهَ ثَلاثًا وَثَلاثِينَ وَكَبَّرَ اللَّهَ ثَلاثًا وَثَلاثِينَ فَتْلِكَ تِسْعَةٌ وَتِسْعُونَ وَقَالَ تَمَامَ الْمِائَةِ : لا إِلَهَ إِلاّ اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ غُفِرَتْ خَطَايَاهُ وَإِنْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ',
  'اللَّهُمَّ أجِرْنِي مِنَ النَّارِ',
  'إِنَّ النَّاسَ إِذا اجْتَمَعُوا فِي مَجْلِس ثُمَّ فَارَقُوهُ وَلَمْ يَذْكُرُوا اللهَ',
  'وَلَمْ يُصَلُّوا عَلَى النَّبِي يَكُونُ حَسْرَةً عَلَيْهِم فِي الآخِرَةِ وَإِن دَخَلُوا الجَنَّة',
  'لاَ إِلهَ إِلاَّ اللّه',
  'اللَّهُمَّ صَلِّ عَلَى سَيِّدِنَا مُحَمَّدٍ وَ عَلَى آلِهِ وَ صَحْبِهِ وَ سَلِّم',
  'ربِّ اغْفِرْ لِي وَلِلْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ',
  'بِاسْمِ اللهِ',
  'بِسمِ اللَّه، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الخُبْثِ وَالخَبَائِث',
  'الحَمدُ لِلَّهِ الَّذِي أَذهَبَ عَنِّي الأَذَى وَعَافَانِي',
  'اللَّهُمَّ بَارِك لَنَا فِيْمَا رَزَقْتَنَا وَ قِنَا عَذَابَ النَّار',
  'بِسْمِ الله',
  'بِسْمِ اللهِ أَوَّلَهُ وَآخِرَه',
  'الحَمْدُ للهِ الذِي أطْعَمَنَا وَسَقَانَا وَجَعَلَنَا مُسْلِمِيْن',
  '« اللَّهُمَّ إِنّي أَسْأَلُكَ وأَتَوَجَّهُ إِلَيكَ بِنَبِيِّكَ مُحَمَّدٍ نَبِيِّ الرَّحْمَةِ. يا مُحَمَّدُ إِنِّي أَتَوَجَّهُ بِكَ إِلى رَبِّي فِي حَاجَتِي لِتُقْضَى لِي »',
  'اللَّهُمَّ إنِّي أسْتَوْدِعُكَ هَذَا المَكَانَ وَ مَا فِيهِ وَ مَنْ فِيه',
  'أَعُوذُ بِوَجْهِ اللَّهِ الْعَظِيمِ الَّذِي لَيْسَ شَيْءٌ أَعْظَمَ مِنْهُ وَبِكَلِمَاتِ اللَّهِ التَّامَّاتِ الَّتِي لَا يُجَاوِزُهُنَّ بَرٌّ وَلَا فَاجِرٌ وَبِأَسْمَاءِ اللَّهِ الْحُسْنَى مَا عَلِمْتُ مِنْهَا وَمَا لَمْ أَعْلَمْ مِنْ شَرِّ مَا خَلَقَ وَذَرَأَ وَبَرَأَ',
  'أعوذُ بكلماتِ اللهِ التّامّة مِن كُلّ شَيطانٍ وهامّةٍ ومن كُلّ عَينٍ لامّةٍ',
  'اللّهُم ذا السُّلطانِ العَظيمِ والمَنِّ القديمِ، ذا الرّحمةِ الكريم وليَّ الكلماتِ التّامّاتِ والدَّعوات المُستَجابات عافِني من أنفس الجنِّ وأعْيُنِ الإنسِ.',
  'اللهمَّ ذَا السلطانِ العظيمِ والْمَنِّ القديـمِ ذَا الرحـمةِ الكريـم',
  'وَلِيَّ الكلماتِ التَّاماتِ والدَّعواتِ المستجاباتِ',
  'عافِ حَسنًا وحُسينًا من أنفسِ الجِنِّ وأَعيُنِ الإنسِ',
  'اللهُمَّ إنِّي أعُوذُ بِكَ مِنَ الهَمِّ والحَزَن وأعُوذُ بِكَ مِنَ العَجْزِ والكَسَل وأعُوذُ بِكَ مِنَ الجُبْنِ والبُخْلِ وأعُوذُ بِكَ من غَلبَةِ الدَّينِ وقَهْرِ الرِّجَالِ. (لقضاء الدّين)',
  'وَجَّهْتُ وَجْهِيَ لِلَّذِي فَطَرَ السَّموَاتِ وَالأَرْضَ',
  'حَنِيفاً مُسْلِماً وَمَا أَنَا مِنَ الْمُشْرِكِينَ',
  'إنَّ صَلاَتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ العَالَمِينَ لاَ شَرِيكَ لَهُ',
  'وَبِذَلِكَ أُمِرْتُ وَأَنَا مِنَ الْمُسْلِمِينَ',
  'التَّحِيَّاتُ المُبَارَكَاتُ الصَّلَوَاتُ الطَّيِّبَاتُ لِلّه',
  'السَّلاَمُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللهِ وَبَرَكَاتُهُ',
  'السَّلاَمُ عَلَيْنَا وَعَلَى عِبَادِ اللهِ الصَّالِحِينَ',
  'أَشْهَدُ أَن لاَ إِلهَ إِلاَّ اللهُ وَأَشْهَدُ أَنَّ مُحَمَّداً رَسُولُ الله',
  'اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ',
  'كَمَا صَلَّيْتَ عَلَى إبْرَاهِيمَ وَعَلَى آلِ إبْرَاهِيمَ',
  'إنَّكَ حَمِيدٌ مَجِيدٌ',
  'اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ',
  'كَمَا بَارَكْتَ عَلَى إبْرَاهِيمَ وَعَلَى آلِ إبْرَاهِيمَ',
  'قَالَ رَسُولُ اللَّهِ ﷺ: « إِذَا فَرَغَ أَحَدُكُمْ مِنَ التَّشَهُدِ الآخِرِ فَلْيَتَعَوَّذْ بِاللَّهِ مِنْ أَرْبَعٍ: مِنْ عَذَابِ جَهَنَّمَ، وَمِنْ عَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ، وَمِنْ شَرِّ الْمَسِيحِ الدَّجَّالِ »',
  '« اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ، وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ، وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْمَأْثَمِ وَالْمَغْرَمِ »',
  '« اللَّهُمَّ اغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ، وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ، وَمَا أَسْرَفْتُ وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي، أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لا إِلهَ إِلا أَنْتَ »',
  '« قُلْ اللَّهُمَّ إِنِّي ظَلَمْتُ نَفْسِي ظُلْمًا كَثِيرًا وَلا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ، فَاغْفِرْ لِي مَغْفِرَةً مِنْ عِنْدِكَ وَارْحَمْنِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ »',
  '« لا إِلهَ إِلا اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَىءٍ قَدِيرٌ. اللَّهُمَّ لا مَانِعَ لِمَا أَعْطَيْتَ، وَلا مُعْطِيَ لِمَا مَنَعْتَ، وَلا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ »',
  '« لا إِلهَ إِلا اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَىءٍ قَدِيرٌ، لا حَوْلَ وَلا قُوَّةَ إِلا بِاللَّهِ، لا إِلهَ إِلا اللَّهُ وَلا نَعْبُدُ إِلا إِيَّاهُ، لَهُ النِّعْمَةُ وَالْفَضْلُ، وَلَهُ الثَّنَاءُ الْحَسَنُ، لا إِلهَ إِلا اللَّهُ مُخْلِصِينَ لَهُ الدِّينَ وَلَوْ كَرِهَ الْكَافِرُونَ »',
  '« مُعَقِّبَاتٌ لا يَخِيبُ قَائِلُهُنَّ أَوْ فَاعِلُهُنَّ دُبُرَ كُلِّ صَلاةٍ مَكْتُوبَةٍ ثَلاثًا وَثَلاثِينَ تَسْبِيحَةً، وَثَلاثًا وَثَلاثِينَ تَحْمِيدَةً، وَثَلاثًا وَثَلاثِينَ تَكْبِيرَةً »',
  'وَفِي حَدِيثٍ ءَاخَرَ لِمُسْلِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ رَسُولِ اللَّهِ ﷺ أَنَّ مَنْ فَعَلَ ذَلِكَ وَقَالَ تَمَامَ الْمِائَةِ: « لا إِلهَ إِلا اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَىءٍ قَدِيرٌ غُفِرَتْ ذُنُوبُهُ وَإِنْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ »',
  'وَرَوَى الْبُخَارِيُّ فِي الصَّحِيحِ عَنْ سَعْدِ بنِ أَبِي وَقَّاصٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ رَسُولَ اللَّهِ ﷺ كَانَ يَتَعَوَّذُ دُبُرَ الصَّلاةِ بِهَؤُلاءِ الْكَلِمَاتِ: « اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْجُبْنِ، وَأَعُوذُ بِكَ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ، وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا، وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ »',
  'يَا مُعَاذُ وَاللَّهِ إِنِّي لأُحِبُّكَ ثُمَّ قَالَ: « أُوصِيكَ يَا مُعَاذُ لا تَدَعَنَّ فِي دُبُرِ كُلِّ صَلاةٍ أَنْ تَقُولَ: اللَّهُمَّ أَعِنِّي عَلَى ذِكْرِكَ وَشُكْرِكَ وَحُسْنِ عِبَادَتِكَ »',
  '« اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْكُفْرِ وَالْفَقْرِ وَعَذَابِ الْقَبْرِ »',
  '« اللَّهُمَّ اغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي، أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لا إِلهَ إِلا أَنْتَ »',
  '« إن من أفضل أيامكم يوم الجمعة فأكثروا عليّ من الصلاة فيه فإن صلاتكم معروضة علي »',
  '« مَنْ صلّى عليَّ عَصْرَ يومِ الجُمُعَةِ ثمانينَ مرّةً غَفَرَ اللهُ لهُ ذنوبَ ثمانينَ عامًا »',
  '« تقول: اللهم صل على محمد عبدك ونبيك ورسولك النبي الأمي وتعقد واحدة »',
  'اللَّهُمَّ إنَّهُ بَلَغَنِي أَنَّ نَبِيَّكَ قَالَ مَاءُ زَمْزَمَ لِمَا شُرِبَ لَه',
  'اللَّهُمَّ إِنِّي أَشْرَبُهُ مُسْتَشْفِيًا بِهِ فَاشْفِنِي وَاغْفِرْ لِي',
  'اللَّهُمَّ إِنِّي أَسْأَلُكَ عِلْمًا نَافِعًا وَرِزْقًا وَاسِعًا وَشِفَاء مِنْ كُلِّ دَاء',
  '« بِاسْمِ اللهِ، اللَّهُمَّ اِفْتَحْ لِـي أَبْوَابَ رَحْـمَتِكَ وَانْشُرْ عَلَيَّ خَزَائِنَ عِلْمِكَ »',
  'اللَّهُمَّ صَلِّ على سَيّدِنَا مُحمَّدٍ صَلَّى اللهُ عَلَيْهِ وسَلَّم اللَّهُمَّ افْتَحْ لي أبْوابَ رَحْمَتِكَ',
  '« مَنْ قَالَ فِي سُوقٍ مَنْ هَذِهِ الأَسْوَاقِ لا إِلهَ إِلا اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيِي وَيُمِيتُ وَهُوَ حَيٌّ لا يَمُوتُ بِيَدِهِ الْخَيْرُ وَهُوَ عَلَى كُلِّ شَىءٍ قَدِيرٌ، كَتَبَ اللَّهُ عَزَّ وَجَلَّ لَهُ أَلْفَ أَلْفِ حَسَنَةٍ، وَمَحَا عَنْهُ أَلْفَ أَلْفِ سَيِّئَةٍ، وَبَنَى لَهُ بَيْتًا فِي الْجَنَّةِ »',
  'باركَ اللَّهُ لكَ',
  'باركَ اللَّهُ عليكَ وجَمعَ بينكما في خير',
  'باركَ اللَّهُ لكُلِّ واحدٍ منكُما في صاحِبهِ وجَمَعَ بينكما في خير',
  '« بَارَكَ اللَّهُ لَكَ وَبَارَكَ عَلَيْكَ وَجَمَعَ بَيْنَكُمَا فِي خَيْرٍ »',
  '« أسألك من خيرها و خير ما جبلت عليه وأعوذ بك من شرّها و شرّ ما جبلت عليه »',
  'الحَمْدُ لله',
  'يَرْحَمُكَ الله',
  'يَهْدِيكُمُ الله ويُصْلِحُ بَالَكُم',
  'اللَّهُمَّ لا سَهْلَ إلاّ مَا جَعَلْتَهُ سَهْلا وَإِنَّكَ تَجْعَلُ الحَزْنَ إِذَا شِئْتَ سَهْلا',
  'بسم الله، ربّي الله، حسبي الله، توكّلت على الله، اعتصمت بالله، فوّضت أمري إلى الله، ما شاء الله، لا قوّة إلاّ بالله',
  'اللهم صلِّ صلاةً كاملةً، وسلِّم سلامًا تامًّا على سيِّدنا محمّد، الذي تَنحَلُّ به العُقد وتَنفَرجُ به الكُرَب، وتُقضى به الحوائجُ، وتُنالُ به الرَّغائِب وحُسنُ الخَواتيم، ويُستسقى الغَمام بوجهِه الكَريم، وعلى ءاله وصحبه وسلِّم.',
  'فضل هذه الصيغة: تسمى هذه الصيغة في الصلاة على النبيّ بـ "الصلاة النارية" وتقال: [4444] مرة لقضاء الحاجة. أو [100] مرة لرؤية الرسول الأعظم صلى الله عليه وسلم',
  '« اللَّهُمَّ رَبَّ النَّاسِ، أَذْهِبِ البَأْسَ، اِشْفِ أَنْتَ الشَّافِـي، لاَ شِفَاءَ إِلاَّ شِفَاءُكَ »',
  'باِسْمِ اللهِ، بِاسْمِ اللهِ، بِاسْمِ اللهِ',
  'أعُوذُ بِعِزَّةِ اللهِ وَقُدْرَتِهِ مِنْ شَرِّ ما أجِدُ وأُحاذِرُ (للشّفاء، 7 مرّات)',
  'بِسْمِ اللهِ أَرْقِيكَ مِنْ كُلِّ شَىءٍ يُؤذِيكَ مِنْ شَرِّ كُلِّ نَفْسٍ أَو عَيْنِ حَاسِدٍ',
  'اللهُ يَشْفِيكَ بِسْمِ اللهِ أَرْقِيك',
  'الـحَمْدُ للهِ الَّذِي كَسَانِـي مَا أُوَارِي بِهِ عَوْرَتـِي وأَتَـجَمَّلُ بِهِ فِي حَيَاتِـي',
  'اللَّهُمَّ غَارَتِ النُّجُومُ وَهَدَأَتِ الْعُيُونُ وَأَنْتَ حَيٌّ قَيُّومٌ',
  'لا تَأْخُذُكَ سِنَةٌ وَلا نَوْمٌ ، يَا حَيُّ يَا قَيُّومُ أَهْدِئْ لَيْلِي وَأَنِمْ عَيْنِي',
  'الحَمْدُ لله اللَّهمَّ كما حَسَّنْتَ خَلْقِي فَحَسِّنْ خُلُقِي',
  'الـحَمْدُ للهِ الَّذِي خَلَقَنِـي فَسَوَّانِـي، اللَّهُمَّ كَمَا حَسَّنْتَ خَلْقِي فَحَسِّنْ خُلُقِي',
  '« اللَّهُمَّ أَدْخِلْهُ عَلَيْنَا بِالْأَمْنِ وَالْإِيمَانِ، وَالسَّلَامَةِ وَالْإِسْلَامِ، وَرِضْوَانٍ مِنَ الرَّحْمَنِ، وَجِوَارٍ (أيْ حِفْظٍ) مِنَ الشَّيْطَانِ »',
  'بِسْمِ الإلــــٰهِ وَبِهِ بَدَيْنَا وَلَوْ عَبَـدْنا غَيْرَهُ شَـقِينَا وَحَبـَّذَا رَبـًّا وَحَبَّ دِينــا وَحَبَّذَا مُـحَمَّدٌ هَادِينَا',
  '{سُبْحَانَ رَبِّكَ رَبِّ الْعِزَّةِ عَمَّا يَصِفُونَ (180) وَسَلَامٌ عَلَى الْمُرْسَلِينَ (181) وَالْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ (182)} [سورة الصافات 180 - 182]',
  'اللَّهُمَّ رَادَّ الضَّالَّةِ، وَهَادِيَ الضَّلَالَةِ تَهْدِي مِنَ الضَّلَالَةِ، ارْدُدْ عَلَيَّ ضَالَّتِي بِقُدْرَتِكِ وَسُلْطَانِكَ، فَإِنَّهَا مِنْ عَطَائِكَ وَفَضْلِكَ',
  'يا جامعَ النَّاسِ ليومٍ لا ريبَ فيه اجمعْ عَلَيَّ ضَالَّتِي',
  'اللَّهُمَّ رَادَّ الضَّالَّةِ، هَادِيَ الضَّالَّةِ، تَهْدِي مِنَ الضَّلَالَةِ، رُدَّ عَلَيَّ ضَالَّتِي، بِعِزَّتِكَ وَسُلْطَانِكَ، فَإِنَّهَا مِنْ فَضْلِكَ وَعَطَائِكَ',
  'سورة الفاتحة (3 مرات)',
  'ءاية الكرسي (3 مرات)',
  'سورة القدر (3 مرات)',
  'سورة النصر (3 مرات)',
  'سورة الإخلاص (3 مرات)',
  'سورة الفلق (3 مرات)',
  'سورة الناس (3 مرات)',
  'سَلَامٌ قَوْلًا مِّن رَّبٍّ رَّحِيمٍ (21 مرات)',
  'رَبَّنَا آتِنَا مِن لَّدُنكَ رَحْمَةً وَهَيِّئْ لَنَا مِنْ أَمْرِنَا رَشَدًا (21 مرات)',
  'لا إله إلا الله (121 مرات)',
  'لفظ الجلالة الله (121 مرات)',
  'الصَّلاةُ وَالسَّلامُ عَلَيكَ يَا سَيِّدِي يَا رَسُولَ اللهَ يَا أَحْمَد قَلَّتْ حِيلَتِي وَأَنتَ وَسِيلَتِي فَأَدْرِكْنِي (21 مرات)',
  'يَا عِبَادَ الله أغِيثُونَا (3 مرات)',
  'اللّهُم أَمِدَّنَا بِأمدَادِ السَّيِّد أَحمَد الرِّفَاعِيِّ (3 مرات)',
  'الفاتحة على النية (مرة واحدة)',
  '« لَوْ أَنَّ أَحَدَكُمْ إِذَا أَتَى أَهْلَهُ قَالَ : بِسْمِ اللَّه ، اللَّهُمَّ جَنِّبْنَا الشَّيْطَانَ ، وَجَنِّب الشَّيْطَانَ مَا رَزَقْتَنَا ، فَقُضِيَ بَيْنَهُمَا وَلَدٌ لَمْ يَضُرَّهُ »',
  '« لَمْ يَضُرَّهُ شَيْطَانٌ أَبَداً »',
  'اللهُمَّ أنْتَ رَبِّي لا إلهَ إلا أنْتَ خَلَقْتَنِي وَأنَا عَبْدُكَ وَأنَا عَلَى عَهْدِكَ وَوَعْدِكَ ما اسْتَطَعْتُ أعُوْذُ بِكَ مِن شَرِّ مَا صَنَعْتُ أبُوْءُ لَكَ بِنِعْمَتِكَ عَلَيَّ وَأبُوْءُ بِذَنْبِي فَاغْفِرْ لِي فَإنَّهُ لا يَغْفِرُ الذُّنُوبَ إلا أنْتَ',
  'رَبِّ اغْفِرْ لِي وَلِوَالِدَيَّ وَارْحَمْهُمَا كَمَا رَبَّيانِي صَغِيرا',
  'اللهم اجعله صَيِّبًا هنيئا',
  'اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ وَأَسْتَقْدِرُكَ بِقُدْرَتِكَ وَأَسْأَلُكَ مِنْ فَضْلِكَ فَإِنَّكَ تَعْلَمُ وَلَا أَعْلَمُ وَتَقْدِرُ وَلَا أَقْدِرُ وَأَنْتَ عَلَّامُ الغُيُوب اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الأَمْرَ خَيْرٌ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ فِي عَاجِلِ أَمْرِي وَءَاجِلِه فَاقْدِرْهُ لِي وَيَسِّرْهُ لِي وَإِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الأَمْرَ شَرٌّ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ فِي عَاجِلِ أَمْرِي وَءَاجِلِه فَاصْرِفْهُ عَنِّي وَاصْرِفْنِي عَنْهُ وَاقْدِرْ لِي الخَيْرَ حَيْثُ كَانَ وَرَضِّنِي بِهِ',
  'رَبَّنا ءاتِنا فِي الدُّنيا حَسَنَةً وفِي الآخِرَةِ حَسَنَةً، وقِنَا عَذَابَ النَّار',
  'بَارَكَ اللَّهُ فِيكَ',
  'أَحْسَنَ اللَّهُ إلَيْكَ',
  'جَزَاكَ اللَّهُ خَيْراً',
  'بِاسْمِ اللَّه، اللَّهُمَّ إِنّىِ أَسْأَلُكَ خيْر المَوْلَجِ وَخَيْرَ الْمَخْرَجِ، بِاسْمِ اللَّهِ وَلَجْنا، وَبِاسْمِ اللَّهِ خَرَجْنا، وَعَلَى اللَّهِ رَبِنا تَوَكَّلْنا',
  'الحَمْدُللهِ الذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَ إِلَيْهِ النُّشُور',
  'اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ النَّبِيِّ وَأَزْوَاجِهِ أُمَّهَاتِ الْمُؤْمِنِينَ وَذُرِّيَّتِهِ وَأَهْلِ بَيْتِهِ كَمَا صَلَّيْتَ عَلَى ءَالِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ',
  'اللَّهُمَّ لَكَ صُمْت وَعَلَى رِزْقِكَ أَفْطَرْت',
  'سُبحَانَ الله وَبِحمدِهِ هِيَ سَببٌ لِتَيسيرِ الرِّزقِ، الَّذِي يُكثِرُ من سُبحَانَ الله وَبِحمدِهِ اللهُ تَعَالَى يُيَسِرُ لَهُ بَابَ الرِّزقِ، مَنَافِعُهَا عَظِيمَةٌ.',
  'لا إله إلا اللهُ الملِكُ الحَقُّ المُبين',
  'لتَيْسِير الرِّزْقِ مِائَة مَرّة (يا وَهَّاب) بعدَ صَلاة الضُّحَى.',
  'لتَيْسِير الرِّزْقِ (سُورَة الواقِعَة) بعدَ صَلاة المغرب.',
  'كتابة البسملة خَمسًا وثلاثين مرة لتيسير الرزق يوضع على باب الدكان لرواج البضاعة. (تُكتَبُ البَسمَلَة خمسًا وثَلاثِينَ مَرّةً وتُحمَلُ أو تُعَلَّقُ على بابِ البَيتِ أو الدُّكّان لتَيسِير الرّزْقِ فيهَا سِرٌّ عَظِيم).',
  'وَرَدَ في الحَديث القُدسيّ: "يَا دُنيَا مَن خَدَمَنِي فَاخْدُمِيْهِ ومَن خَدَمَكِ فأَتْعِبِيْه". ومعناه: اللهُ تعالى يُيَسّر الرّزقَ لمن اتّقَى الله واشْتَغَل بطَاعَتِه. ومَعنى "خَدَمَني" في هذا الحديث: أطَاعَني.',
  'عن سَلّام بنِ شُرَحْبِيْلَ عن حَبَّةَ وسَوَاء ابنَي خَالدٍ رَضيَ اللهُ تَعالى عنهُما قَالا أَتَينَا رَسولَ الله صلى الله عليه وسلم فقال : "لَا تَيْئَسَا مِنَ الرّزْقِ مَا تَهَزْهَزَت رُؤوسُكُما فإنّ الإنسَانَ تَلِدُه أُمُّهُ أَحمرَ لا قِشْرَ عَلَيهِ ثم يَرزُقُهُ اللهُ عَزَّ وَجَلّ". هذا حَديثٌ صَحِيحٌ أخرَجَه أَحمَد.',
  'ورَد حديثٌ صَحيح: "مَنْ لَزِمَ الاستِغفَارَ جَعَلَ اللهُ لهُ مِن كُلّ ضِيقٍ مَخرَجًا ومِن كُلّ هَمّ فَرَجًا ورَزقَه مِن حَيثُ لا يَحتَسِب" رواه أبو داود ، وابن ماجه ، والبيهقى عن ابن عباس ورواه أبو داود والطبراني)',
  'لمن يَشكُو الضّيقَ مِن حيث المال أكثِر مِن الاستغفار، استَغفِر الله كلَّ يَوم ثَلاثمائة مَرّة.',
  'مَنْ قَرَأَ هَذَا الدُّعاءَ فِي اليَوْمِ عِشْرِيْنَ مَرَّةً لَم يَرَ قِلَّةً أَبَدًا، وَهُوَ مُجَرَّبٌ صَحِيْحٌ : "بِسْمِ اللهِ الرَّحمنِ الرَّحِيمِ، يَا عَظِيمَ الجَلَالِ، يَا بَدِيعَ الكَمَالِ، يَا كَثِيْرَ النَّوَالِ، يَا دَائِمَ الإِفْضَالِ، يَا حَسَنَ الفَعَالِ، يَا قَائِمُ بِلَا زَوَالٍ، وَصَلَّى اللهُ عَلَى سَيِّدِنَا مُحَمَّدٍ وَعَلَى ءَالِهِ وَصَحْبِهِ وَسَلَّم"',
  'شَخصٍ لم يُرزَق أَولادًا مُنذُ عَشرِ سنِينَ : لِيُكثِرُوا مِنَ الاستِغفَار، ليَلزَم. شَخصٌ لَزِمَ الاستِغفَارَ فرُزِقَ.',
  'وَرَدَ حَدِيثٌ بِإِسْنَادٍ ضَعِيفٌ: "الصُّبْحَةُ تَمْنَعُ الرِّزْقَ"، الصُّبْحَةُ فَمَعْنَاهُ النَّوْمُ بَعْدَ صَلَاةِ الصُّبْحِ (أي أوَّلَ النَّهَارِ)، لَكِنَّهُ إِنْ كَانَ الشَّخْصُ يَنَامُ بِلَا فَائِدَةٍ (هذَا الذِي نَقُولُ) لَا خَيْرَ فِيهِ (لأنَّهُ قَد يَكُونُ نَوْمُهُ لِمَرَضٍ).',
  'بِسْمِ الله ، تَوَكَّلْتُ عَلَى الله ، وَلا حَوْلَ وَلا قُوَّةَ إلا بِالله',
  'اللَّهُمَّ إِنِّي أَعُوذُ بِكَ أَنْ أَضِلَّ أَو أُضَلَّ أَو أَزِلَّ أَو أُزَلَّ، أَو أَظْلِمَ أَو أُظْلَمَ، أَو أَجْهَلَ أَو يُجْهَلَ عَلَيَّ',
  'اللَّهُمَّ صَلِّ عَلَى سَيِّدِنَا مُحَمَّدٍ صَلَّى اللهُ عَلَيْهِ وسَلَّم. اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ',
  '« لـمّا اقترف آدمُ الخطيئة قال : يا ربّ أسألك بحق محمد إلا ما غفرت لي »',
  'سُبْحَانَ الذِي يُسَبِّحُ الرَعْدُ بِحَمْدِهِ وَالمَلائِكَةُ مِنْ خِيفَتِه',
  'اللهُ أكْبَر اللهُ أكْبَر اللهُ أكْبَر سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَٰذَا',
  'وَمَا كُنَّا لَهُ مُقْرِنِينَ وَ إنَّا إلى رَبِّنَا لَمُنْقَلِبُوْن',
  'أسألُ اللهَ العظيمَ ربَّ العرشِ العظيمِ أنْ يشفيَك',
  'أَسْتَوْدِعُكَ اللهَ الَّذِي لاَ تَضِيعُ وَدَائِعُهُ',
  'أستَودِعُ اللَّهَ دِينَكَ وَأَمَانَتَكَ وَخَوَاتِيمَ عَمَلِكَ',
  'اللهُ أكْبَر، اللهُ أكْبَر، اللهُ أكْبَر، اللَّهُمَّ إِنَّا نَسْأَلُكَ في سَفَرِنَا هذا البِرَّ والتَّقوى ومِنَ العَمَلِ ما تَرْضى، اللَّهُمَّ هَوِّنْ علَيْنا سفَرَنَا هذا وَاطْوِ عنَّا بُعْدَهُ، اللَّهُمَّ أَنتَ الصَّاحِبُ في السَّفَرِ وَالخَلِيفَةُ في الأهْلِ، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وعْثَاءِ السَّفَرِ، وكآبةِ المَنظَرِ، وَسُوءِ المُنْقلَبِ في المالِ والأهلِ',
  'نطق الفؤاد وبالغرام أجابكم أنا مذهبي عن حبّكم لا أذهب',
  'الله عظَّمَ قَدْرَ محمّدٍ وأَنالهُ فضلًا لديهِ عظيمًا في مُحكَمِ التَنزيلِ قال لِخلقِهِ صَلُّوا عليهِ وسَلّموا تَسليمًا',
  '« مَنْ صَلَّى عَلَيَّ مِنْ أُمَّتِي صَلاةً مُخْلِصًا مِنْ قَلْبِهِ صَلَّى اللهُ عَلَيْهِ بِها عَشْرَ صَلَواتٍ ورَفَعَهُ بِها عَشْرَ دَرَجاتٍ وكَتَبَ لَهُ بِها عَشْرَ حَسَناتٍ ومَحَا عَنْهُ عَشْرَ سَيِّئاتٍ »',
  '« صَلُّوا عَلَيَّ فَإِنَّها زَكاةٌ لَكُمْ وٱسْأَلُوا اللهَ لِي الوَسِيلَةَ فَإِنَّها دَرَجَةٌ في أَعْلَى الجَنَّةِ لا يَنالُها إِلَّا رَجُلٌ وأَرْجُو أَنْ أَكُونَ أَنا هُوَ »',
  '« إِذا سَمِعْتُمُ الْمُؤَذِّنَ فَقُولُوا مِثْلَ ما يَقُولُ ثُمَّ صَلُّوا عَلَيَّ فَإِنَّهُ مَنْ صَلَّى عَلَيَّ صَلاةً صَلَّى اللهُ عَلَيْهِ بِها عَشْرًا ثُمَّ سَلُوا اللهَ لِي الوَسِيلَةَ فَإِنَّها مَنْزِلَةٌ في الجَنَّةِ لا تَنْبَغِي إِلَّا لِعَبْدٍ مِنْ عِبادِ اللهِ وأَرْجُو أَنْ أَكُونَ أَنا هُوَ فَمَنْ سَأَلَ لِي الوَسِيلَةَ حَلَّتْ لَهُ الشَّفاعَةُ »',
  '« إِنَّ أَوْلَى الناسِ بِي يَوْمَ القِيامَةِ أَكْثَرُهُمْ عَلَيَّ صَلاةً »',
  '« اللهُ يَعْلَمُ إِنِّي لَأُحِبُّكُنَّ »',
  '« يغفر ذنبًا ويكشف كربًا ويرفع قومًا ويضع آخرين »',
  '« سُبحان الّذي يُغَيّر ولا يتغيَّر »',
  '« لَا يَرُدُّ القَضَاءَ إِلّا الدُّعَاءُ »',
  '« إنَّ النّذرَ لا يَرُدُّ منْ قدَرِ اللهِ وإِنّمَا يُستَخْرَجُ بِهِ مِنَ البَخيلِ »',
  '« سألت ربي أربعًا فأعطاني ثلاثًا ومنعني واحدة : سألته أن لا يُكْفِرَ أمتي جملة فأعطانيها وسألته أن لا يهلكهم بما أهلك به الأمم قبلهم فأعطانيها، وسألته أن لا يظهر عليهم عدوًا من غيرهم فيستأصلهم فأعطانيها، وسألته أن لا يجعل بأسهم بينهم فمنعنيها »',
  '« سألت ربي ثلاثًا فأعطاني ثنتين ومنعني واحدة »',
  '« قال لي يا محمد إني إذا قضيت قضاء فإنه لا يرد »',
  'اللّهمّ يا الله يا الله يا الله يا حيّ يا قيّوم يا غفور يا توّاب يا فتّاح يا رزّاق يا واسع يا معين يا باسط يا مبدئ يا وهّاب يا متين ويا حافظ يا وليّ يا كافي يا حسيب يا أرحم الرّاحمين يا ذا المنّ ويا ذا الفضل ويا ذا الجلال والإكرام ويا ذا الطّول والإنعام ويا من تمحو ما تشاء وتثبت ما تشاء ويا من عندك أمّ الكتاب بحقّ أسماءك الحسنى وآياتك العظمى وبحقّ اسمك العظيم الأعظم وبالتجلّي في ليلة النّصف من شعبان المكرّم صلّ على سيّدنا ومولانا وحبيبنا وشفيعنا وملاذنا محمّد رسولك ونبيّك الأكرم صلاة كاملة دائمة تكتبنا بها عندك في هذه اللّيلة المباركة مغفورين لهم مسعودين معمّرين بالخير مرزوقين موفّقين للأذكار والطّاعات والخيرات والحسنات ومستغنين بفضلك في الدّارين عمّن سواك وصلّ على سيّدنا محمّد صلاة تكتبنا بها في هذه اللّيلة من السّعداء والصّالحين وترزقنا بها في الدّارين إيمانا كاملا وكمال اليقين بحقّ سيّدنا محمّد سيّد المرسلين وإمام المتّقين ومحبوب ربّ العالمين وتكشف بها عنا البليات والآفات والعاهات الواردة بإرادتك هذه السّنة لتصيب بها من تشاء من عبادك إنّك مجيب الدّعوات وما ذلك على الله بعزيز وصلّى الله على سيّدنا محمّد وعلى آله وصحبه وسلّم.',
  '« إِذَا سَمِعْتُمُ المُؤَذِّنَ فَقُولُوا كَمَا يَقُولُ ثُمَّ صَلُّوا عَلَيَّ »',
  '« مَن ذَكَرَنِي فَلْيُصَلِّ عَلَيَّ »'
);

-- dhikr : 27 entrées
SELECT count(*) AS "dhikr_a_supprimer" FROM "dhikr" WHERE texte_arabe IN (
  'رَبِّ اغْفِرْ وَارْحَمْ وَاهْدِ لِلسَّبِيلِ الأَقْوَمِ',
  'لا إله إلا الله وحده لا شريك له، أحـد أحـد، لـم يلـد ولـم يولد، ولـم يكـن لـه كفوا أحـد.',
  'اللهُمَّ إِنِّي أُشْهِدُكَ وَأُشْهِدُ حَمَلَتَ عَرْشِك وَ مَلائكَتَكَ وَجَمِيعَ خَلْقِكَ أَنَّكَ أَنْتَ الله لا إلهَ إلا أنْتَ وَحْدَكَ لا شَرِيكَ لك وَأَنَّ مُحَمَّدً عَبْدُكَ وَ رَسُولُك',
  '« كَانَ اللَّهُ وَلاَ مَكَانَ وَهُوَ الآنَ عَلَى مَا عَلَيْهِ كَانَ »',
  '« إنَّ الله خَلَقَ العَرْشَ إِظْهَارًا لِقُدْرَتِهِ وَلَمْ يَتَّخِذهُ مَكَاناً لِذَاتِهِ »',
  'بسمِ الله، الله أكبرُ اللهمَّ إيمانًا بك وتصديقًا بكتابك ووفاءً بعهدِك واتّباعًا لسنةِ نبيك محمدٍ صلى الله عليه وسلم',
  'اللهمَّ اجْعَلْه حجًّا مبرورًا وذنبًا مغفورًا وسعيًا مشكورًا',
  'اللهم اغفر وارحمْ واعفُ عما تعلم وأنتَ الأعزُّ الأكرم، اللهمَّ ءاتنا في الدنيا حسنةً وفي الآخرة حسنةً وقنا عذابَ النار',
  'اللهمَّ ءاتنا في الدنيا حسنةً وفي الآخرة حسنةً وقنا عذابَ النار',
  'سبحانَ الله والحمدُ لله ولا إلهَ إلا الله والله أكبر',
  'بسمِ اللهِ ما شآءَ الله لا يَسُوْقُ الخَيْرَ إِلا الله',
  'بسمِ اللهِ ما شآءَ الله لا يَصْرِفُ السُّوءَ إِلا الله',
  'بسمِ اللهِ ما شآءَ الله مَا كانَ مِن نِّعْمَةٍ فَمِنَ الله',
  'بسمِ اللهِ ما شآءَ الله لا حَوْلَ وَلا قُوَّةَ إِلا بالله',
  'سُبحانَكَ اللهُمَّ رَبَّنَا وَبِحَمدِكَ اللَّهُمَّ اغفِرْ لِي',
  'أصْبَحْنا وأصْبَحَ الـمُلْكُ للهِ وَالحَمْدُ للهِ رَبِّ العَالَمِين',
  'اللَّهُمَّ بِكَ أصْبَحْنا، وَبِكَ أمْسَيْنا، وَبِكَ نَحْيا، وَبِكَ نَمُوتُ وَإِلَيْكَ النُّشُورُ',
  'أَصْبَحْنَا وَأَصْبَحَ الـمُلْكُ للهِ وَالـحَمْدُ للهِ وَالـخَلْقُ وَالأَمْرُ وَاللَّيْلُ وَالنَّهَارُ للهِ',
  'بِسْمِ اللهِ الّذِي لاَ يَضُرُّ مَعَ اسْمِهِ شَىْءٌ في الأَرْضِ وَلا فِي السَّمَاءِ وَهُوَ السَّمِيعُ العَلِيم. (3 مَرّات)',
  'أَعُوذُ بِكَلِمَاتِ اللهِ التّامّاتِ مِن شَرّ مَا خَلَق . (3 مَرّات)',
  'حَسْبِيَ اللهُ لا إِلَـهَ إِلّا هُوَ عَلَيْهِ تَوَكَّلْتُ وَهُوَ رَبُّ العَرْشِ العَظِيم. (7 مَرّات)',
  'يَا حَيُّ يَا قَيُّومُ بِرَحْمَتِكَ أَسْتَغِيثُ، أَصْلِحْ لِي شَأْنِي كُلَّهُ وَلا تَكِلْنِي إِلَى نَفْسِي طَرْفَةَ عَيْن. (3 مَرّات)',
  'رَضِيتُ بِاللهِ رَبّا وَبِالإِسْلاَمِ دِينا وَبِمُحَمَّدٍ نَبِيّا. (3 مَرّات)',
  'أَسْتَغْفِرُ اللهَ الّذِي لا إِلَـهَ إِلّا هُوَ الحَيُّ القَيُّومُ وَأَتُوبُ إِلَيْه. (3 مَرّات)',
  'رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً، وَ فِي الآخِرَةِ حَسَنَةً ، وَقِنَا عَذَابَ النَّارِ . رَبَّنَا لا تُزِغْ قُلُوبَنَا بَعدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِن لَدُنكَ رَحْمَةً، إِنَّكَ أَنتَ الوَهَّابُ.',
  'أعوذُ بِكلماتِ الله التّامّاتِ الّتي لا يُجاوِزُهُنّ بَرٌّ ولا فاجِر من شرِّ ما يَنزِلُ مِن السَّماء وما يَعرُج فيها ومِن شَرِّ ما ذَرَأ في الأرضِ وما يَخرُج مِنها ومِن شَرِّ فِتَنِ اللَّيلِ والنَّهار ومن شرِّ كُلِّ طارقٍ إلَّا طارِقا يَطرُقُ بِخيرٍ يَا رَحمن',
  'أَعُوذُ باللهِ مِنَ الشَّيْطَانِ الرَّجِيم'
);

